    private val emergenciaPack = LibraryContentPack(
        source = "[NÃO VERIFICADO] Rascunho gerado por IA — conferir contra: Diretrizes ACLS, ATLS, ABRAMEDE, AHA, MS Brasil",
        items = listOf(
            LibraryContentItem(id = "emerg_001", title = "Intubação orotraqueal — drogas de indução", category = "CLINICA_MEDICA",
                summary = "Etomidato (estável), cetamina (broncodilatador), propofol (cardiodepressor). Escolha conforme hemodinâmica.",
                content = "Drogas de indução para IOT em emergência: Etomidato 0,3 mg/kg IV (padrão ouro no choque — estável hemodinamicamente, sem hipotensão). Inibição adrenal transitória. Cetamina 1-2 mg/kg IV (broncodilatador, aumenta PA e FC — útil em asma, DPOC, choque). Contraindicada em HAS intracraniana. Propofol 1-2 mg/kg IV (rápido, hipotensor e cardiodepressor — evitar no choque). Midazolam 0,2-0,3 mg/kg IV (hipotensão leve, longa duração). Succinilcolina (bloqueador despolarizante) 1-1,5 mg/kg IV — padrão ouro para sequência rápida (duração 5-10 min). Contraindicado em: hipercalemia, queimaduras >24h, lesão muscular grave, síndrome de imobilização. Rocurônio (não despolarizante) 1-1,2 mg/kg IV — alternativa segura (duração 30-60 min). Reversão com sugamadex 16 mg/kg (bloqueio profundo). Sequência rápida: pré-oxigenação (100% O2 por 3 min) → indução → bloqueador → intubação. Pressão cricoide (Sellick) — controversa, pode piorar visualização.",
                tags = listOf("emergência", "intubação", "iot", "etomidato", "cetamina"), citation = "Diretriz ATLS 2023 - Via Aérea"),
            LibraryContentItem(id = "emerg_002", title = "Sugamadex — reversão de rocurônio/vecurônio", category = "CLINICA_MEDICA",
                summary = "Sugamadex 2-16 mg/kg IV, dose depende da profundidade do bloqueio neuromuscular.",
                content = "Sugamadex (Bridion): ciclodextrina que encapsula rocurônio e vecurônio, revertendo bloqueio neuromuscular. Indicação: reversão de bloqueio por rocurônio/vecurônio (não funciona com outros BNM). Dose: bloqueio moderado (TOF ≥2): 2 mg/kg IV. Bloqueio profundo (TOF 0, PTC 1-2): 4 mg/kg IV. Bloqueio intenso (imediatamente após succinilcolina/rocurônio): 16 mg/kg IV. Início de ação: 1-3 min. Efeitos adversos: bradicardia (raro, <1%), hipotensão, reação alérgica. Vantagens sobre neostigmina (anticolinesterásico): mais rápido, sem necessidade de atropina, funciona em bloqueio profundo. Pode ser usado em vez de succinilcolina para sequência rápida (rocurônio 1,2 mg/kg + sugamadex 16 mg/kg se falha de intubação). Preço elevado limita uso rotineiro. Armazenamento: temperatura ambiente.",
                tags = listOf("urgência", "sugamadex", "rocurônio", "reversão"), citation = "Diretriz ATLS 2023 - Via Aérea"),
            LibraryContentItem(id = "emerg_003", title = "Manejo da via aérea difícil — algoritmo ASA", category = "CLINICA_MEDICA",
                summary = "Algoritmo ASA: máscara laríngea, bougie (guia elástico), cricotireoidostomia se falha de IOT e ventilação.",
                content = "Algoritmo de Via Aérea Difícil (ASA 2022): Pré-avaliação: Mallampati (3-4), distância tireomentoniana (<3 dedos), abertura de boca (<2 dedos), pescoço curto/espesso, história de intubação difícil. Avaliar: não consigo ventilar? não consigo intubar? Se não ventila + não intuba → plano de resgate. Algoritmo: 1) Chamar ajuda. 2) Reposicionar cabeça, pressão laríngea externa, bougie (guia elástico introdutor). 3) Máscara laríngea (ML/ML-I-gel) ou combitubo. 4) Se ML ventila → manter ML, repetir IOT via ML, ou acordar. 5) Se ML não ventila → cricotireoidostomia de emergência. Cricotireoidostomia: incisão vertical na membrana cricotireóidea (entre tireoide e cricoide), introduzir cânula/tubo 4-5mm. Via aérea cirúrgica definitiva. Videolaringoscópio (GlideScope, McGrath) é primeira linha em via aérea difícil prevista. Kit de cricotireoidostomia percutânea (Seldinger) disponível em todos os hospitais. Se paciente está estável e prevê-se dificuldade extrema: IOT acordado com fibra óptica.",
                tags = listOf("urgência", "via aérea difícil", "cricotireoidostomia", "asa"), citation = "Diretriz ASA 2022 - Via Aérea Difícil"),
            LibraryContentItem(id = "emerg_004", title = "Cricotireoidostomia — técnica e indicação", category = "CLINICA_MEDICA",
                summary = "Cricotireoidostomia de emergência quando não ventila + não intuba. Incisão na membrana cricotireóidea.",
                content = "Cricotireoidostomia de urgência (cricotiroidotomia): Indicação: não consigo ventilar (máscara), não consigo intubar, máscara laríngea não funciona. Contraindicações: <5 anos de idade (risco de lesão de subglote — preferir acesso cirúrgico por traqueostomia nessa faixa etária). Técnica percutânea (Seldinger): 1) Hiperextensão do pescoço. 2) Palpar membrana cricotireóidea (entre cartilagem tireoide e cricoide). 3) Punção com agulha acoplada a seringa com SF. 4) Aspirar — se bolhas de ar → confirma. 5) Passar fio-guia. 6) Dilatador + cânula. Técnica cirúrgica: incisão vertical na pele, dissecar até membrana, incisar membrana horizontalmente, introduzir tubo/cânula 4-5mm. Complicações: sangramento, lesão de cordas vocais, perfuração traqueal posterior, enfisema subcutâneo, estenose subglótica tardia. Após cricotireoidostomia, converter para traqueostomia em 48-72h se permanência >7 dias prevista. Tubo de cricotireoidostomia tem cuff para proteger via aérea inferior.",
                tags = listOf("urgência", "cricotireoidostomia", "cricotireoidostomia", "via aérea"), citation = "Diretriz ATLS 2023 - Via Aérea"),
            LibraryContentItem(id = "emerg_005", title = "Choque anafilático — tratamento", category = "CLINICA_MEDICA",
                summary = "Adrenalina 0,3-0,5 mg IM (face lateral da coxa). Repetir a cada 5-15 min se necessário. Suporte com O2, volume, anti-histamínicos.",
                content = "Anafilaxia (reação de hipersensibilidade tipo I, IgE-mediada): Tratamento de primeira linha: Adrenalina (epinefrina) 0,3-0,5 mg IM (1:1.000, 0,3-0,5 mL) na face lateral da coxa (pode repetir a cada 5-15 min). Mecanismo: α-agonista (reverte vasodilatação, edema, ↓ liberação de histamina) + β-agonista (broncodilatação, ↑ força cardíaca). Se choque refratário à adrenalina IM: adrenalina EV em BOMBA DE INFUSÃO, iniciar 0,05-0,1 mcg/kg/min e titular, com monitorização contínua. NÃO administrar bolus de 0,5-1 mg EV em paciente com pulso — essa é a dose de PCR; em paciente perfundindo pode causar crise hipertensiva, isquemia miocárdica e arritmia fatal. Suporte: oxigênio 100%, acesso venoso, cristaloides (20 mL/kg). Anti-histamínicos (H1 + H2): difenidramina 25-50 mg EV + famotidina 20 mg EV (a ranitidina foi retirada do mercado mundialmente em 2020 por contaminação com NDMA — não prescrever). Corticoide: metilprednisolona 125 mg EV (prevenir reação bifásica — 20% dos casos). Broncoespasmo refratário: salbutamol neb. Sinais de anafilaxia: início súbito (minutos) com urticária/prurido + angioedema + broncoespasmo/disfonia + hipotensão + náusea/vômito/diarreia. Causas comuns: drogas (ATB, AINEs, contraste), alimentos (amendoim, crustáceos, ovos, leite), picadas de inseto. Alta após 6-8h (risco de reação bifásica). Prescrever autoinjetor de adrenalina (Epipen) na alta. Encaminhamento ao alergologista.",
                tags = listOf("urgência", "anafilaxia", "adrenalina", "choque"), citation = "Diretriz ACAAI 2023 - Anafilaxia"),
            LibraryContentItem(id = "emerg_006", title = "Intoxicação por paracetamol — tratamento", category = "CLINICA_MEDICA",
                summary = "Dose tóxica >150 mg/kg. Tratamento: N-acetilcisteína (NAC) protocolo de 21h (150 mg/kg + 50 mg/kg + 100 mg/kg).",
                content = "Intoxicação por paracetamol: Dose tóxica: >150 mg/kg adultos, >100 mg/kg crianças em <24h. Fases: I (0-24h) — assintomático; II (24-72h) — náusea, vômito, dor HD; III (72-96h) — necrose hepática maciça, IRA, encefalopatia, óbito. Tratamento: N-acetilcisteína (NAC, Acetilcisteína, Fluimucil) Protocolo de 21h (MS Brasil): Dose de ataque: 150 mg/kg EV em 15-60 min (em 200 mL SG 5%). Segunda dose (4h após): 50 mg/kg EV em 4h (500 mL). Terceira dose (16h após): 100 mg/kg EV em 16h (1.000 mL). Total: 300 mg/kg em 21h. Protocolo alternativo: NAC 140 mg/kg VO (dose única), depois 70 mg/kg 4/4h (17 doses = 72h). Indicação: ingeriu >150 mg/kg nas últimas 8h, nível sérico de paracetamol >150 mcg/mL em 4h (nomograma de Rumack-Matthews). Eficácia: máxima se início <8h. Reduz hepatotoxicidade de 60% para <5% se iniciar em 8h. Se >24h da ingestão e sem NAC: considerar transplante hepático (critérios King's College). Carvão ativado 50g VO se <2h da ingestão. Avaliar transaminases, TP/INR, bilirrubinas, creatinina, glicose. Insulinoterapia se hipoglicemia.",
                tags = listOf("urgência", "paracetamol", "n-acetilcisteína", "intoxicação"), citation = "Diretriz MS Brasil 2023 - Intoxicação por Paracetamol"),
            LibraryContentItem(id = "emerg_007", title = "Intoxicação por salicilato — alcalinização", category = "CLINICA_MEDICA",
                summary = "Bicarbonato de sódio EV para alcalinizar urina (pH >7,5) — aumenta excreção renal de salicilato.",
                content = "Intoxicação por salicilato (AAS, ácido acetilsalicílico): Dose tóxica: >150 mg/kg (leve), >300 mg/kg (moderada), >500 mg/kg (grave). Fisiopatologia: acidose mista (acidose lática + hiperventilação + ácido salicílico). Quadro: zumbido, hiperventilação, náusea/vômito, hipertermia, desidratação, confusão, coma, convulsão, hemorragia (hipoprotrombinemia). Hemogasometria: alcalose respiratória + acidose metabólica. Salicilemia >40 mg/dL = toxicidade. Tratamento: Alcalinização da urina (aumenta excreção de salicilato 10-20x): bicarbonato de sódio 8,4% — 1-2 mEq/kg EV em 1h, depois 100-150 mEq em 1L SG 5% a 2-3 mL/kg/h. Alvo: pH urinário >7,5-8,0 (monitorizar a cada 2-4h). Manter K+ normal (hipocalemia impede alcalinização). Carvão ativado: 50g VO se ingestão <4h (liga salicilato). Hemodiálise: indicada se salicilemia >100 mg/dL (aguda), >60 mg/dL (crônica), ou sinais de toxicidade grave (coma, IRA, acidose refratária, SDRA). Hidratação agressiva. Suporte: ventilação mecânica com hiperventilação (evitar hipoxemia). A hiperventilação compensatória NÃO deve ser suprimida. Monitorizar glicemia, K+, Ca++, Mg++. Alcalinização deve ser monitorizada (risco de hipocalcemia e alcalose grave).",
                tags = listOf("urgência", "salicilato", "bicarbonato", "intoxicação", "aas"), citation = "Diretriz MS Brasil 2023 - Intoxicação por Salicilato"),
            LibraryContentItem(id = "emerg_008", title = "Intoxicação por opioides — naloxona", category = "CLINICA_MEDICA",
                summary = "Naloxona 0,4-2 mg EV, repetir a cada 2-3 min até reversão da depressão respiratória. Reversão rápida, duração curta (20-90 min).",
                content = "Intoxicação por opioides (heroína, morfina, fentanil, tramadol, codeína, metadona, oxicodona): Quadro: depressão respiratória (FR <10, PaCO2 >50, hipoxemia), miose puntiforme, rebaixamento de consciência (coma, escala Glasgow baixa), bradicardia, hipotensão. Tratamento: Naloxona (Narcan) — antagonista opioide µ (mecanismo: reversão completa e imediata). Dose inicial: 0,04-0,4 mg IV (0,1-2 mL da diluição 0,4 mg/mL). Repetir a cada 2-3 min se necessário. Dose de ataque: 2 mg IV se PCR suspeita de opioide. Início: 1-2 min IV, 5 min IM. Duração: 20-90 min (mais curta que a maioria dos opioides — risco de re-narcotização). Cuidado: abstinência aguda violenta (náusea, vômito, agitação, lacrimejamento, diarreia, taquicardia, sinais de hipertensão) — titular doses baixas (0,04 mg) se o paciente não está em PCR. Se PCR (suspeita de overdose fatal): naloxona 2 mg IV/IM, iniciar RCP. Infusão contínua de naloxona: 0,25-1 mg/h IV (se dose total >2 mg para reverter) — titular para manter FR >12 sem abstinência grave. Metadona: meia-vida longa (24-36h), requer infusão prolongada. Alta: após 12-24h de observação (sem necessidade de naloxona). Programas de redução de danos. Notificação.",
                tags = listOf("urgência", "naloxona", "opioide", "intoxicação", "overdose"), citation = "Diretriz WHO 2023 - Intoxicação por Opioides"),
            LibraryContentItem(id = "emerg_009", title = "Intoxicação por benzodiazepínicos — flumazenil", category = "CLINICA_MEDICA",
                summary = "Flumazenil 0,2-1 mg EV. Cuidado: em pacientes com epilepsia, pode precipitar convulsão refratária. Não usar em ingestão de pró-convulsivantes.",
                content = "Intoxicação por benzodiazepínicos (diazepam, clonazepam, alprazolam, midazolam, lorazepam): Quadro: sedação, sonolência, ataxia, disartria, depressão respiratória leve a moderada (raramente grave se BZD isolado, exceto em idosos ou combinação com álcool/outros depressores). Tratamento: Flumazenil 0,2 mg EV (1 mL) em 30s. Se reversão insuficiente, repetir 0,3 mg (30s) e depois 0,5 mg a cada minuto (dose máxima total 3-5 mg). Início: 1-2 min. Duração: 30-60 min (mais curta que a maioria dos BZD — pode precisar infusão 0,1-0,5 mg/h se rebote). Efeitos colaterais: pode precipitar convulsão em: dependente crônico de BZD (abstinência aguda), e epilepsia em uso de valproato/carbamazepina (reverte proteção anticonvulsivante). Contraindicações: ingestão concomitante de heterocíclicos (tricíclicos) — convulsão refratária. Na overdose isolada de BZD sem depressão respiratória severa: manejo de suporte (hidratação, proteção de VA) — reverter nem sempre é necessário. Se ingestão múltipla de drogas (ex: BZD + álcool): suporte ventilatório é a prioridade. Uso de flumazenil em overdose mista: riscos > benefícios (exceto se indicação precisa). Não usar se convulsão iminente ou epilepsia descontrolada.",
                tags = listOf("urgência", "flumazenil", "benzodiazepínico", "intoxicação"), citation = "Diretriz MS Brasil 2023 - Intoxicação por BZD"),
            LibraryContentItem(id = "emerg_010", title = "Intoxicação por metanol/etilenoglicol", category = "CLINICA_MEDICA",
                summary = "Fomepizol (15 mg/kg) ou etanol + hemodiálise. Bicarbonato se acidose metabólica grave. Tratamento precoce reduz sequelas.",
                content = "Intoxicação por metanol (álcool metílico) ou etilenoglicol (anticongelante): Mecanismo: metanol → ácido fórmico → acidose metabólica + lesão oftálmica. Etilenoglicol → ácido oxálico → IRA + hipocalcemia. Quadro: metanol — turvação visual, escotomas, cegueira, coma, acidose metabólica com hiato aniônico e osmolar aumentados. Etilenoglicol — coma, convulsão, IRA, hipocalcemia, cristais de oxalato na urina, acidose metabólica. Diagnóstico: gasometria com hiato aniônico >12 e hiato osmolar >10, detecção direta de álcool no sangue. Tratamento: Fomepizol (Antizol) — inibidor da álcool desidrogenase (primeira escolha na maioria dos serviços modernos): dose de ataque 15 mg/kg EV, depois 10 mg/kg 12/12h por 48h, depois 15 mg/kg até etilenoglicol <20 mg/dL. Alternativa se fomepizol indisponível: Etanol (álcool etílico) — competir pela enzima. Ataque: 600-800 mg/kg (7,6-10 mL/kg de etanol a 10% EV ou 1-2 mL/kg de whisky VO). Manutenção: 100-200 mg/kg/h. Alvo: etanolemia 100-150 mg/dL. Hemodiálise: indicada se acidose refratária (pH <7,15-7,20), IRA, metanol >50 mg/dL (ou etilenoglicol >50 mg/dL), disfunção orgânica, coma. Ácido folínico (leucovorin) 1-2 mg/kg 6/6h por 24h — auxilia metabolização do ácido fórmico (metanol). Bicarbonato de sódio EV se acidose grave (pH <7,2). Prognóstico: bom se tratado precocemente. Sequelas: cegueira (metanol), IRC (etilenoglicol).",
                tags = listOf("urgência", "metanol", "etilenoglicol", "fomepizol", "hemodiálise"), citation = "Diretriz MS Brasil 2023 - Intoxicações por Álcool Tóxico"),
            LibraryContentItem(id = "emerg_011", title = "Síndrome serotoninérgica — tratamento", category = "CLINICA_MEDICA",
                summary = "Hipertermia, rigidez, mioclonia, confusão. Tratar: ciproheptadina, benzodiazepínicos, resfriamento. Suspender drogas serotoninérgicas.",
                content = "Síndrome serotoninérgica: emergência causada por excesso de serotonina central (ISRS, IMAO, MDMA, tramadol, linezolida, dextrometorfano, lítio, triptanos). Início: minutos a horas após exposição. Critérios de Hunter (≥1): clônus espontâneo ou induzível + agitação + diaforese, clônus ocular + agitação + diaforese, clônus inducível + rigidez + temperatura >38°C + clônus ocular ou inducível. Tratamento: 1) Suspender imediatamente todos os agentes serotoninérgicos. 2) Antagonista serotoninérgico: ciproheptadina (Periactin) — 12 mg VO/sonda ataque, depois 2 mg a cada 2h até melhora (máx 32 mg/dia). 3) Benzodiazepínicos: diazepam 5-10 mg IV ou midazolam (controle de agitação, rigidez, convulsão). 4) Resfriamento agressivo se hipertermia >39,5°C (banho com gelo, paracetamol). 5) Cuidados de suporte: hidratação, monitorização cardíaca, suporte ventilatório. Não usar: antipsicóticos (pioram rigidez e hipertermia). Propranolol (bloqueia metabolismo de serotonina). Bromocriptina (piora). A maioria se resolve em 24-72h com tratamento de suporte. Prognóstico: bom se reconhecido precocemente. Mortalidade <1% com tratamento adequado (>10% sem tratamento). Diagnóstico diferencial: síndrome neuroléptica maligna (início mais gradual, dias-semanas, rigidez + febre, CPK alto, sem clônus).",
                tags = listOf("urgência", "serotonina", "ciproheptadina", "hipertermia"), citation = "Diretriz ABRAMEDE 2023 - Síndrome Serotoninérgica"),
            LibraryContentItem(id = "emerg_012", title = "Status asmático — tratamento", category = "CLINICA_MEDICA",
                summary = "Broncodilatador inalatório contínuo, corticoide EV, sulfato de magnésio 2g IV. Intubar se PaCO2 >45 ou exaustão.",
                content = "Status asmático (crise asmática grave refratária): Tratamento: 1) Oxigênio para manter SpO2 ≥92%. 2) Broncodilatador inalatório: salbutamol 5 mg neb contínuo (ou 4-8 jatos com espaçador a cada 20 min) + ipratrópio 0,5 mg neb 6/6h. 3) Corticoide sistêmico: hidrocortisona 200 mg EV ataque, depois 50 mg 6/6h ou metilprednisolona 60-80 mg EV 6/6h. 4) Sulfato de magnésio 2g IV em 20 min (reduz necessidade de intubação). 5) Se refratário: salbutamol 1 mg/h EV em infusão (diluir 5 mg em 250 mL SF) — monitorizar arritmias e hipocalemia. 6) Considerar heliox (He 70% + O2 30%) — reduz resistência ao fluxo aéreo. 7) Ventilação não invasiva (CPAP/BiPAP) — benefício limitado (usar com cautela). 8) Intubação: PCO2 >45 mmHg (normalização de PCO2 na crise asmática = exaustão), rebaixamento, exaustão, PCR. Técnica: IOT com cetamina (broncodilatador), tubo ≥8mm, ventilação com baixa FR (10-12 irpm), baixo VC (6-8 mL/kg), tempo expiratório longo (I:E 1:4) para evitar auto-PEEP/air trapping. A hipercapnia permissiva é aceitável. Suporte na UTI. Causas de piora: infecção (ATB se suspeita), má adesão, falta de CI, alergia, AINE.",
                tags = listOf("urgência", "asma grave", "status asmático", "magnésio", "intubação"), citation = "Diretriz ATLS 2023 - Crise Asmática"),
            LibraryContentItem(id = "emerg_013", title = "Edema agudo de pulmão — tratamento", category = "CLINICA_MEDICA",
                summary = "Oxigênio, furosemida 40-80 mg IV, morfina 2-5 mg IV, nitrato SL/IV, CPAP (VNI) se refratário.",
                content = "Edema Agudo de Pulmão (EAP) cardiogênico: Quadro: dispneia súbita, ortopneia, DPN, B3, estertores crepitantes até ápices, cianose, extremidades frias, PA elevada (na maioria). Tratamento imediato: 1) Oxigênio: máscara não reinalante 15 L/min (alvo SpO2 >92%). 2) Furosemida 40-80 mg IV (dobrar se já em uso crônico). Reduz pré-carga (venodilatação antes de diurese). Ação em 5-15 min. 3) Morfina 2-5 mg IV (reduz ansiedade, ↓ tônus simpático, venodilatação). Cuidado: depressão respiratória (uso cauteloso). 4) Nitrato sublingual (isossorbida 5 mg) ou IV (nitroprussiato 0,25-10 mcg/kg/min, ou nitroglicerina 10-400 mcg/min). Se crise hipertensiva: nitroprussiato (0,25-10 mcg/kg/min) para reduzir pré e pós-carga. 5) CPAP (VNI) — pressão 10-15 cmH2O, recruta alvéolos, reduz trabalho respiratório, melhora troca gasosa. Reduz necessidade de intubação. 6) Posição semi-sentada (reduz pré-carga). 7) Se FA com resposta ventricular rápida: controle de FC com BBl (metoprolol 5 mg IV). Se PAS <80 mmHg: considerar choque cardiogênico (dobutamina, noradrenalina, BIA). Causas: IC descompensada, IAM, FA, HAS, excesso de volume, miocardite, estenose aórtica. Intubar se PaO2 <60 ou PaCO2 >55 apesar de CPAP.",
                tags = listOf("urgência", "eap", "edema agudo pulmão", "furosemida", "cpap"), citation = "Diretriz ACLS 2023 - Edema Agudo de Pulmão"),
            LibraryContentItem(id = "emerg_014", title = "Arritmia ventricular (TV sem pulso/FV) — RCP com choque", category = "CLINICA_MEDICA",
                summary = "FV/TV sem pulso: desfibrilação 200J bifásica, RCP 2 min e reavaliar. Amiodarona 300 mg se refratário.",
                content = "Parada cardiorrespiratória (PCR) por Fibrilação Ventricular (FV) ou Taquicardia Ventricular sem pulso (TVSP): Algoritmo ACLS: 1) Choque: desfibrilação com 200J bifásico (ou 360J monofásico). 2) RCP 2 min (30:2), reavaliar ritmo. 3) 2º choque 200J. 4) RCP 2 min, acesso IV/IO, intubar. 5) Adrenalina 1 mg IV a cada 3-5 min (após o 2º choque). 6) 3º choque 200J. 7) Amiodarona 300 mg IV (primeira dose) + RCP. 8) 4º choque 200J + adrenalina. 9) Amiodarona 150 mg IV (segunda dose, se necessário) + RCP. 10) Choque + adrenalina a cada 2 min. Causas reversíveis (5Hs e 5Ts): hipovolemia, hipóxia, hidrogênio (acidose), hipo/hipercalemia, hipotermia; tensão pneumotórax, tamponamento cardíaco, toxinas (overdose), trombose coronariana (IAM), trombose pulmonar (TEP maciço). Desfibrilação precoce é o principal preditor de sobrevida (cai 10% a cada min de atraso). RCP de alta qualidade: compressão torácica 5-6 cm, 100-120/min, retorno total do tórax, minimizar interrupções. PCR testemunhada com ritmo chocável: sobrevida 30-50% com desfibrilação precoce. Hipotermia terapêutica: manter 32-36°C por 24h após retorno da circulação espontânea (RCE).",
                tags = listOf("urgência", "pcra", "fv", "tv", "desfibrilação", "acls"), citation = "Diretriz AHA 2023 - ACLS"),
            LibraryContentItem(id = "emerg_015", title = "Hipotermia terapêutica pós-PCR", category = "CLINICA_MEDICA",
                summary = "Manter 32-36°C por 24h após RCE (retorno da circulação espontânea). Reduz lesão neurológica e mortalidade.",
                content = "Hipotermia Terapêutica (controle de temperatura): Indicação: adultos em coma (Glasgow <8, sem comandos verbais ou motores) após RCE, com PCR de qualquer ritmo. Objetivo: reduzir metabolismo cerebral, inflamação e excitotoxicidade. Alvo de temperatura: 32-36°C por 24h (intervalo >32°C mantém proteção sem aumento significativo de arritmias ou sangramento clinicamente relevante). Métodos: infusão de SF gelado (30 mL/kg, 4°C), mantas térmicas, cateter intravascular de controle de temperatura. Prevenir tremores: sedação (propofol, midazolam), bloqueio neuromuscular se necessário (rocurônio). Fase de reaquecimento: 0,25-0,5°C/h (evitar reaquecimento rápido — piora edema cerebral). Não ultrapassar 37°C nas primeiras 72h. Febre pós-PCR: tratar agressivamente (paracetamol, mantas). Avaliar função neurológica após 72h (antes disso, sedação e BNM mascaram exame). Exames prognósticos: EEG (status epiléptico?), potenciais evocados (N20), RM. O prognóstico neurológico favorável em 50-60% dos pacientes com PCR extra-hospitalar e ritmo chocável. Prognóstico reservado se: PCR >20 min sem RCP, >30 min com RCP sem RCE, lactato >10, idade >85. Discussão sobre doação de órgãos se sem perspectivas neurológicas em 72h-7 dias.",
                tags = listOf("urgência", "hipotermia", "pós-pcr", "neurológico"), citation = "Diretriz AHA 2023 - PCR"),
            LibraryContentItem(id = "emerg_016", title = "Tromboembolismo pulmonar de alto risco — trombólise", category = "CLINICA_MEDICA",
                summary = "TEP de alto risco (instabilidade hemodinâmica): trombólise sistêmica com alteplase 100 mg em 2h.",
                content = "TEP de alto risco (maciço): PAS <90 mmHg por >15 min ou necessidade de vasopressores. Estratificação de risco: PESI simplificado >1 ou sPESI ≥1, instabilidade hemodinâmica, disfunção de VD no ecocardiograma (dilatação VD, TAPSE <16, sinal de McConnell, achatamento septal), troponina elevada (lesão miocárdica). Tratamento (em pacientes de alto risco sem contraindicação absoluta): Trombólise sistêmica — alteplase (rt-PA) 100 mg IV em 2h, ou 50 mg/h por 1h. Administrar quanto antes (quanto mais precoce, maior benefício). Efeitos colaterais: hemorragia intracraniana (1-3%), sangramento maior (10-20%). Contraindicações absolutas: AVC hemorrágico prévio, cirurgia intracraniana ou intraespinhal <3 meses, sangramento ativo, neoplasia intracraniana. Contraindicações relativas: HSA, cirurgia <2 semanas, TCE <3 meses, IAM <1 mês, HAS não controlada (>180/110), gestação, idade >75 anos. Após trombólise: iniciar heparina (HNF ou HBPM) quando TTPa <2x normal (geralmente 2-4h após). Se contraindicado: embolectomia cirúrgica (circulação extracorpórea) ou cateter-directed (fragmentação/aspiração do trombo). Ecocardiograma transesofágico intra-operatório pode confirmar diagnóstico e guiar tratamento. Prognóstico: mortalidade intra-hospitalar 15-25% (sem trombólise, mortalidade >50%).",
                tags = listOf("urgência", "tep", "trombólise", "alteplase", "embolia"), citation = "Diretriz ESC 2019 - TEP"),
            LibraryContentItem(id = "emerg_017", title = "Dissecção de aorta — dor em facada", category = "CLINICA_MEDICA",
                summary = "Dor torácica em facada, irradiação interescapular, diferença de PA entre MMSS. Tratamento cirúrgico (tipo A) ou clínico (tipo B).",
                content = "Dissecção de aorta: Suspeitar em: dor torácica abrupta em facada (lancinante), com irradiação para dorso/abdome/interescapular. Diferença de PA >20 mmHg entre os braços. Sopro aórtico (insuficiência aórtica) novo. Déficit de pulso (carótida, braquial, femoral). Síncope, AVC, IAM, isquemia de medula/membros. Fatores de risco: HAS, idade >60, síndrome de Marfan/Ehlers-Danlos, valva aórtica bicúspide, aortite, gravidez. Diagnóstico: TC de tórax com contraste (padrão ouro — sensibilidade 100%), ecocardiograma transesofágico (alternativa se paciente instável), RNM. Classificação Stanford: Tipo A (ascendente) — cirurgia emergencial. Tipo B (descendente) — tratamento clínico. Tratamento pré-operatório (estabilização): betabloqueador IV (esmolol, labetalol) para FC 60 bpm e PAS 100-120 mmHg. Depois vasodilatador (nitroprussiato). Analgesia (morfina IV). Tipo A: cirurgia de emergência — substituição da aorta ascendente + possível reparo de valva aórtica. Mortalidade sem cirurgia: 1-2% por hora nas primeiras 48h. Com cirurgia: mortalidade 10-30%. Tipo B: manejo clínico (BB + vasodilatador) + TEVAR (Ressecção Endovascular de Aneurisma Torácico) em caso de complicações (ruptura, má perfusão dos ramos viscerais, crescimento).",
                tags = listOf("urgência", "dissecção aorta", "dor torácica", "emergência"), citation = "Diretriz ACC/AHA 2022 - Doença Aórtica"),
            LibraryContentItem(id = "emerg_018", title = "Hemorragia digestiva alta — estabilização", category = "CLINICA_MEDICA",
                summary = "Estabilização: hemoderivados se choque, IBP (omeprazol 80 mg EV ataque + 8 mg/h), endoscopia precoce (<24h).",
                content = "Hemorragia Digestiva Alta (HDA) — manejo inicial: Estabilização: Acesso venoso periférico (2 calibrosos) + reposição volêmica com cristaloides (Ringer lactato 20 mL/kg) se hipotensão. Transfusão de hemácias se Hb <7 (alvo 7-9), ou se choque refratário. Avaliar: hematêmese (viva ou borra de café), melena (fezes pretas), enterorragia (se maciça). Sonda nasogástrica: lavagem com SF para confirmar sangramento e limpar estômago para endoscopia (não é obrigatória). IBP EV: omeprazol 80 mg IV em bolus, depois 8 mg/h IV contínuo (ou pantoprazol 80 mg + 8 mg/h). Estabiliza o coágulo, reduz ressangramento antes e após endoscopia. Endoscopia digestiva alta: idealmente <24h (mas <12h se choque ou hematêmese ativa). Intervenção: esclerose ou bandagem elástica de varizes esofágicas, termocoagulação/clipe/APC para úlcera péptica, injeção de adrenalina. Sangramentos varicosos: terlipressina 1-2 mg IV 4/4h + antibioticoprofilaxia (ceftriaxona 1g/dia) + bandagem elástica. Se sangramento não varicoso: Rockall ≥3 ou Blatchford ≥1 (ver tópicos específicos). Avaliação cirúrgica se endoscopia falha (cirurgia/embolização). Escore AIMS65: 5 itens — albumina <3, INR >1,5, alteração de consciência, PAS <90, idade >65. Mortalidade global: 5-10% (maior se instável).",
                tags = listOf("urgência", "hda", "hemorragia digestiva", "ppla"), citation = "Diretriz ESGE 2023 - HDA"),
            LibraryContentItem(id = "emerg_019", title = "Hemorragia digestiva baixa — causas", category = "CLINICA_MEDICA",
                summary = "Causas: diverticulose, angiodisplasia, pólipos, neoplasia, DII, hemorroidas. Colonoscopia é padrão ouro.",
                content = "Hemorragia Digestiva Baixa (HDB): sangramento distal ao ligamento de Treitz (intestino delgado, cólon, reto). Causas: diverticulose (40% — mais comum em idosos, sangramento indolor e abundante), angiodisplasia (20% — displasia vascular, mais em ceco/cólon direito), pólipos/neoplasia (10-15% — sangramento crônico, ferropriva), doença inflamatória intestinal (10% — Crohn, colite ulcerativa — sangue + muco + diarreia), hemorroidas/fissura anal (5-10%), lesão anorectal (pólipo, CA retal), isquemia, infecção. Diagnóstico: anuscopia (excluir origem hemorroidária). Colonoscopia: padrão ouro — identifica causa + trata (hemostasia: clipe, APC, termocoagulação). Preparo entérico com manitol/PEG antes do procedimento (idealmente <24h). Se sangramento ativo sem identificação: enterorragia — colonoscopia com visualização pobre. Alternativas: angioTC com contraste (identifica extravasamento de contraste), cintilografia com hemácias marcadas (para sangramento intermitente, sensibilidade maior), arteriografia (embolização se sangramento ativo >0,5-1 mL/min). Estabilização: mesma da HDA (acesso venoso, cristaloides, transfusionar se Hb <7). Reverter anticoagulantes. Se sangramento instável e não identificado: laparotomia exploradora + intraoperatória enteroscopia. Avaliar se a hemorragia é de instabilidade hemodinâmica (choque) — nesse caso, pensar em HDA mascarada (rápida passagem pelo trânsito intestinal com enterorragia por HDA).",
                tags = listOf("urgência", "hdb", "hemorragia digestiva", "divertículo"), citation = "Diretriz ESGE 2023 - HDB"),
            LibraryContentItem(id = "emerg_020", title = "Abscesso perianal — drenagem", category = "CLINICA_MEDICA",
                summary = "Abscesso perianal: drenagem cirúrgica imediata é o tratamento definitivo. ATB apenas se celulite extensa ou imunossuprimido.",
                content = "Abscesso perianal (glândulas anais infectadas, mais comum em homens 30-50 anos): Quadro: dor anal intensa e pulsátil (piora ao sentar), tumoração perianal dolorosa (hiperemia, calor), febre. Tipos: perianal superficial (mais comum, 50-60%), isquiorretal (profundo, cavidade isquiorretal), interesfinctérico (entre esfíncteres), supra-elevador (pelve). Diagnóstico: clínico + US endoanal (se dúvida). TC/RM se suspeita de abscesso profundo ou doença de Crohn. Tratamento: Drenagem cirúrgica imediata é o tratamento definitivo. Abscesso perianal: incisão e drenagem — incisão radial próxima ao ânus (evita lesão de esfíncter), drenagem completa, curetagem de septos, colocar dreno (Penrose ou algodão). Abscesso profundo: drenagem sob anestesia geral, possível confecção de seton (fio de seda) se fístula associada. ATB: indicado apenas se celulite extensa, imunossupressão, prótese valvar, sepse, ou sinais de Fournier (crepitação, necrose, toxicidade sistêmica). Esquema: ceftriaxona 1g 12/12h + metronidazol 500 mg 8/8h. Após drenagem, 30-50% evoluem com fístula anal (drenagem crônica). Encaminhamento ao coloproctologista para fistulotomia eletiva. Não postergar drenagem aguardando ATB — a drenagem em si é o tratamento.",
                tags = listOf("urgência", "abscesso perianal", "drenagem", "fístula anal"), citation = "Diretriz ASCRS 2023 - Abscesso Perianal"),
            LibraryContentItem(id = "emerg_021", title = "Priapismo — tratamento", category = "CLINICA_MEDICA",
                summary = "Priapismo >4h: aspiração cavernosa + fenilefrina intracavernosa. Se refratário, derivação cirúrgica (shunt).",
                content = "Priapismo (ereção persistente >4h sem estimulação ou após): Tipos: isquêmico (baixo fluxo, veno-oclusivo — receptor de emergência) — o mais comum, emergência, risco de fibrose cavernosa e disfunção erétil. Não isquêmico (alto fluxo, arterial) — geralmente pós-trauma, não emergencial. Causas de priapismo isquêmico: drogas (trazodona, antidepressivos, antipsicóticos, heparina, cocaína), anemia falciforme (10-40% dos pacientes), trauma, tumores pélvicos, leucemia, malária. Tratamento escalonado (prioridade: urgência para isquêmico <4-6h): 1) Analgesia + sedação. 2) Aspiração cavernosa (agulha 19G) + lavagem com SF (50-100 mL). 3) Fenilefrina intracavernosa (agonista alfa-1): 200-500 mcg a cada 5-10 min (máx 1.000 mcg em 1h). Diluir em 1mL de SF. Monitorizar PA, FC (risco de hipertensão grave, arritmia). Contraindicado: IMAO. 4) Se refratário: derivação cavernoso-esponjosa (shunt Winter, shunt Ebbehøj, ou shunt Quackels). 5) Em falciforme: hidratação vigorosa, analgesia, oxigênio, alcalinização, transfusão simples ou eritrocitoférese. Se duração >24h: fibrose irreversível (disfunção erétil permanente). Tratamento da causa base. Discutir implante peniano precoce se fibrose estabelecida.",
                tags = listOf("urgência", "priapismo", "fenilefrina", "anemia falciforme"), citation = "Diretriz EAU 2023 - Priapismo"),
            LibraryContentItem(id = "emerg_022", title = "Torção testicular — emergência cirúrgica", category = "CLINICA_MEDICA",
                summary = "Torção testicular: cirurgia em até 6h para salvar testículo. Dor testicular súbita + sinal de Prehn negativo + reflexo cremastérico ausente.",
                content = "Torção testicular: emergência urológica (perda testicular >80% se >12h). Mais comum em recém-nascidos e púberes (<25 anos). Quadro: dor testicular súbita e intensa (especialmente se acordou com dor), náusea/vômito, dor abdominal baixa. Exame: testículo elevado, doloroso, horizontalizado (sinal de ângulo ausente), reflexo cremastérico AUSENTE (diferencial com orquiepididimite), sinal de Prehn negativo (dor não melhora com elevação testicular). Diagnóstico: clínico na maioria! US Doppler com fluxo testicular reduzido/ausente confirma. Se alta suspeita clínica, não atrasar cirurgia para exame de imagem. Tratamento: cirurgia de emergência (exploração escrotal + destorção + orquidopexia bilateral). Técnica: destorção manual antes da cirurgia (abrir pela rotação medial, abrir como abrir um livro) — pode ser tentada se imediato, mas não substitui cirurgia. Cirurgia: incisão escrotal, destorção, avaliar viabilidade testicular (corante?). Se viável (coloração rosa, sangramento): orquidopexia (fixar testículo na bolsa escrotal). Orquidopexia contralateral profilática (risco de torção 30% no lado oposto). Se inviável: orquiectomia. Prognóstico: <6h: sobrevida testicular 90-100%. 6-12h: 50%. >12h: <10-20%. >24h: 0%. Causa de infertilidade mesmo que testículo salvo (lesão de reperfusão). Diferencial: orquiepididimite (febre, dor gradual, reflexo cremastérico presente, sinal de Prehn positivo, urina alterada). Tratar ATB (ceftriaxona + doxiciclina).",
                tags = listOf("urgência", "torção testicular", "emergência", "urologia"), citation = "Diretriz EAU 2023 - Torção Testicular"),
            LibraryContentItem(id = "emerg_023", title = "Síndrome compartimental — fasciotomia", category = "CLINICA_MEDICA",
                summary = "Síndrome compartimental: pressão intracompartimental >30 mmHg. Fasciotomia de emergência para salvar membro.",
                content = "Síndrome Compartimental Aguda: compressão microvascular crítica dentro de um compartimento osteofacial fechado. Mais comum: perna (compartimento anterior), antebraço (compartimento volar). Causas: fratura (principal — tíbia, antebraço, fêmur), esmagamento, queimadura elétrica/térmica, isquemia-reperfusão (síndrome de Volkmann), hematoma, picada de cobra, imobilização gessada apertada. Quadro: dor desproporcional ao exame (mais precoce), dor à flexão passiva dos dedos (alongamento do músculo isquêmico), parestesia, paralisia (tardia), palidez, falta de pulso (MUITO tardia — os 5 Ps: pain, pallor, paresthesia, pulselessness, paralysis). O pulso pode estar presente! Pressão intracompartimental >30 mmHg (ou delta P = PAD - P compartimental <30 mmHg) = indicação de fasciotomia. Tratamento: Fasciotomia de emergência — abertura cirúrgica completa de todos os compartimentos afetados. Na perna: duas incisões longitudinais (anterior-peroneal e posterior superficial-profunda) abrem 4 compartimentos. No antebraço: incisão volar + dorsal (compartimentos flexor e extensor). Pele deixada aberta (não fechar a pele) — pode ser fechada secundariamente ou enxertada em 5-7 dias. Se não tratada em <6h, isquemia irreversível: necrose muscular → contratura de Volkmann, insuficiência renal por rabdomiólise, amputação. A fasciotomia precoce é o único tratamento. Não esperar pela falta de pulso! Profilaxia: elevar membro ao nível do coração, evitar gesso circular apertado, monitorizar sinais precoces.",
                tags = listOf("urgência", "síndrome compartimental", "fasciotomia", "trauma"), citation = "Diretriz ATLS 2023 - Síndrome Compartimental"),
            LibraryContentItem(id = "emerg_024", title = "Queimaduras — regra dos 9 e fórmula de Parkland", category = "CLINICA_MEDICA",
                summary = "Regra dos 9 (superfície corporal queimada). Fórmula de Parkland: 4 mL/kg/%SC queimada nas primeiras 24h (metade nas primeiras 8h).",
                content = "Queimaduras — manuseio inicial: Regra dos 9 (adulto): cabeça e pescoço = 9%, tronco anterior = 18%, tronco posterior = 18%, cada membro superior = 9%, cada membro inferior = 18%, períneo = 1%. Em crianças: cabeça 18%, cada membro inferior 14%. Avaliar profundidade: 1º grau (epiderme — eritema, dor, sem bolha) → tratar conservador. 2º grau superficial (derme papilar — bolha, base rosada, dolorosa) → limpeza + curativo. 2º grau profundo (derme reticular — bolha, base pálida, menos dolorosa). 3º grau (total — carbonizado, indolor, acastanhado, sem perfusão). Fórmula de Parkland (reposição volêmica): 4 mL Ringer lactato / kg / %SC queimada nas primeiras 24h. Metade nas primeiras 8h (contadas da hora da queimadura, não da chegada ao hospital), metade nas 16h seguintes. Manter débito urinário alvo 0,5-1 mL/kg/h (adulto), 1-1,5 mL/kg/h (criança). Alvo de PVC 5-10. Exemplo: homem 70 kg, 30% SC queimada: 4 × 70 × 30 = 8.400 mL → 4.200 mL nas primeiras 8h (525 mL/h), 4.200 mL nas 16h seguintes (262 mL/h). Internação: crianças <10% SCQ, adultos >20% SCQ, queimadura de 3º grau >5%, lesão inalatória, olhos/orelhas/períneo/face/genitália, elétrica ou química. Tratar lesão inalatória: oxigênio, broncoscopia, intubação precoce se estridor/fumo/rouquidão. Escarotomia de emergência se queimadura circunferencial (diminui perfusão de extremidades). Profilaxia antitetânica. Analgesia (morfina IV), curativos com sulfadiazina de prata, evitar hipotermia. Transferir para centro de queimados.",
                tags = listOf("urgência", "queimadura", "parkland", "regra dos 9"), citation = "Diretriz ATLS 2023 - Queimaduras"),
            LibraryContentItem(id = "emerg_025", title = "Suporte básico de vida (SBV) — algoritmo RCP", category = "CLINICA_MEDICA",
                summary = "Reconhecer PCR, chamar ajuda, iniciar compressões 30:2, usar DEA. Compressões 5-6 cm, 100-120/min.",
                content = "Suporte Básico de Vida (BLS — AHA 2023): Algoritmo: 1) Reconhecer PCR: vítima não responde, sem respiração ou gasping (respiração agônica), sem pulso carotídeo (>10 seg). 2) Chamar ajuda: acionar emergência (SAMU 192) + buscar DEA (desfibrilador externo automático). 3) Iniciar RCP: compressões torácicas de alta qualidade: frequência 100-120/min, profundidade 5-6 cm (adulto), permitir retorno total do tórax entre compressões, minimizar interrupções (<10 seg). Relação compressão:ventilação = 30:2 (independente de 1 ou 2 socorristas). 4) Ventilação: abrir via aérea (inclinação da cabeça + elevação do mento), selar com máscara, ventilar 1 segundo cada (peito eleva). 5) DEA: ligar, seguir instruções de voz. Apenas DEA analisa ritmo e administra choque. Ambos os socorristas devem se manter seguros quando o DEA libera choque. 6) Se choque indicado: certifique-se de que ninguém toca na vítima, aperte o botão de choque, imediatamente retomar RCP 30:2. 7) Repetir ciclos de 2 min (5 ciclos 30:2) até: vítima responder, chegada de ajuda avançada, ou socorrista exausto. Cadeia de sobrevivência extra-hospitalar: reconhecimento precoce + RCP precoce + desfibrilação precoce + ALS + cuidados pós-PCR. Cada minuto sem desfibrilação reduz sobrevida em 7-10%. RCP por transeunte duplica ou triplica sobrevida. Treine a leigos!",
                tags = listOf("urgência", "sbv", "rcp", "compressões", "dea"), citation = "Diretriz AHA 2023 - BLS"),
        )
    )

