    private val pediatriaPack = LibraryContentPack(
        source = "[NÃO VERIFICADO] Rascunho gerado por IA — conferir contra: Diretrizes SBP, AAP, OMS, MS Brasil - Pediatria",
        items = listOf(
            LibraryContentItem(id = "peds_001", title = "Curva de crescimento (OMS) — percentis e escore Z", category = "CLINICA_MEDICA",
                summary = "Curvas OMS para peso, estatura, IMC e PC por idade. Escore Z < -2 = desnutrição. > +2 = excesso.",
                content = "Curvas de crescimento OMS 2006-2007 (padrão ouro): Indicadores: peso para idade, estatura/comprimento para idade, IMC para idade, perímetro cefálico (PC) para idade (<2 anos). Escore Z: desvio-padrão em relação à mediana. Z = (medida do paciente - mediana da população de referência) / DP da referência. Classificação: Z > +3 — muito acima; Z > +2 — acima; Z entre -2 e +2 — eutrófico; Z < -2 — déficit; Z < -3 — muito abaixo. Desnutrição: peso-para-idade Z < -2 (baixo peso), estatura-para-idade Z < -2 (nanismo/baixa estatura), IMC-para-idade Z < -2 (magreza). Excesso de peso: IMC-para-idade Z > +1 (sobrepeso), > +2 (obesidade), > +3 (obesidade grave). Acompanhamento: avaliar mensalmente no 1º ano, trimestralmente no 2º, semestralmente até 5 anos, anualmente após. Velocidade de crescimento: >5 cm/ano antes da puberdade. Acelerada na puberdade. Registrar em gráfico específico. Avalie tendência (canal de crescimento), não apenas ponto único. Se houver desvio significativo (cruzamento de 2 ou mais canais): investigar (hipotireoidismo, GH, síndromes genéticas, DII, má absorção, distúrbios alimentares).",
                tags = listOf("pediatria", "crescimento", "oms", "percentil", "escore z"), citation = "Diretriz SBP 2023 - Crescimento e Desenvolvimento"),
            LibraryContentItem(id = "peds_002", title = "Teste do pezinho — doenças rastreadas", category = "CLINICA_MEDICA",
                summary = "Teste do pezinho básico (3º-5º dia) + ampliado. Fenilcetonúria, hipotireoidismo congênito, fibrose cística, anemia falciforme, hiperplasia adrenal congênita, deficiência de biotinidase.",
                content = "Teste do pezinho (Triagem Neonatal Biológica): realizado por punção de calcâneo entre 3º e 5º dia de vida (ideal 48-72h após início da alimentação proteica e >12h de vida). Doenças rastreadas pelo SUS (básico, 6 doenças): Fenilcetonúria (PKU) — fenilalanina >4 mg/dL → dieta restrita em fenilalanina. Hipotireoidismo congênito — TSH elevado → reposição com levotiroxina. Doença falciforme (HbSS) e outras hemoglobinopatias — eletroforese de Hb. Fibrose cística (mucoviscidose) — tripsina imunorreativa (IRT) elevada → confirmação com teste do suor. Hiperplasia adrenal congênita (HAC) — 17-OH progesterona elevada → reposição de corticoide. Deficiência de biotinidase → reposição de biotina. Teste ampliado (privado, >30 doenças): adiciona: galactosemia, toxoplasmose congênita, deficiência de G6PD, aminoacidopatias (maple syrup urine, homocistinúria), acidúrias orgânicas, distúrbios da beta-oxidação (MCAD), imunodeficiência combinada grave (SCID), atrofia muscular espinhal (SMA). Importância: diagnóstico precoce previne sequelas irreversíveis (retardo mental, morte). Coleta em papel filtro, encaminhar ao laboratório de referência. Resultado em 7-15 dias. Se alterado: convocar família e confirmar.",
                tags = listOf("pediatria", "teste do pezinho", "triagem neonatal", "fenilcetonúria"), citation = "Diretriz MS Brasil 2023 - Triagem Neonatal"),
            LibraryContentItem(id = "peds_003", title = "Teste da orelhinha (emissões otoacústicas)", category = "CLINICA_MEDICA",
                summary = "Emissões otoacústicas evocadas (EOA) entre 24-48h de vida. Falha = encaminhar ao fonoaudiólogo para BERA.",
                content = "Teste da Orelhinha (Triagem Auditiva Neonatal — TAN): exame não invasivo que avalia a função coclear (células ciliadas externas). Realizado entre 24-48h de vida, com o bebê dormindo ou calmo. Sonda com microfone é colocada no conduto auditivo externo, emite estímulos sonoros e capta as emissões otoacústicas evocadas (EOA) de volta. Resultado: 'passa' (resposta presente nos dois ouvidos) ou 'falha' (resposta ausente em um ou ambos). Causas de falsa falha: cerume, líquido amniótico no conduto, agitação, prematuridade, otite média secretora. Se falha: repetir após 2-4 semanas. Se falha persistente (2 falhas): encaminhar ao fonoaudiólogo para BERA (Brainstem Evoked Response Audiometry — potenciais evocados auditivos de tronco cerebral). Diagnóstico precoce de perda auditiva (>30 dB é significativa). Intervenção até 6 meses (aparelho auditivo, implante coclear se necessário) é crucial para desenvolvimento da linguagem. Fatores de risco para perda auditiva: prematuridade <32 sem, baixo peso <1.500g, hipóxia perinatal, meningite, hiperbilirrubinemia (exsanguineotransfusão), CMV congênito, história familiar de surdez hereditária, uso de ATB ototóxicos. OMS recomenda triagem universal até 1 mês, diagnóstico até 3 meses, intervenção até 6 meses.",
                tags = listOf("pediatria", "teste da orelhinha", "emissões otoacústicas", "audição"), citation = "Diretriz SBP 2023 - Triagem Auditiva Neonatal"),
            LibraryContentItem(id = "peds_004", title = "Teste do olhinho (reflexo vermelho)", category = "CLINICA_MEDICA",
                summary = "Reflexo vermelho (teste de Bruckner) ao nascimento. Falha = catarata congênita, retinoblastoma, glaucoma congênito.",
                content = "Teste do Olhinho (Teste do Reflexo Vermelho de Bruckner): exame de triagem visual neonatal. Técnica: oftalmoscópio direto a 30-50 cm dos olhos do bebê, iluminar ambos os olhos simultaneamente. Normal: Reflexo vermelho simétrico e brilhante em ambos os olhos (imagem avermelhada/laranja) — resultado da transiluminação da retina. Anormal (falha): assimetria (reflexo mais escuro em um olho), reflexo branco (leucocoria — indica catarata congênita, retinoblastoma, toxoplasmose congênita, persistência de vítreo primário hiperplásico, descolamento de retina), reflexo cinza/opaco (catarata), reflexo ausente. Leucocoria: suspeitar de: catarata congênita (lente opaca), retinoblastoma (tumor retiniano — mais comum CA intraocular infantil), toxoplasmose congênita, doença de Coats. Conduta se anormal: encaminhamento urgente ao oftalmologista. CATARATA CONGÊNITA: cirurgia até 6-8 semanas de vida (risco de ambliopia irreversível). RETINOBLASTOMA: emergência oncológica, encaminhar urgente ao oncologista oftalmológico. Exames complementares: ultrassom ocular, TC/RM de órbitas. O teste deve ser repetido em consultas de puericultura (1º mês, 2º mês, 4º mês, 6º mês, 1 ano).",
                tags = listOf("pediatria", "teste do olhinho", "reflexo vermelho", "catarata"), citation = "Diretriz SBP 2023 - Triagem Ocular Neonatal"),
            LibraryContentItem(id = "peds_005", title = "Teste do coraçãozinho (oximetria de pulso)", category = "CLINICA_MEDICA",
                summary = "Oximetria de pulso em MSD + MID entre 24-48h de vida. Sat <95% ou diferença >3% = suspeita de cardiopatia congênita crítica.",
                content = "Teste do Coraçãozinho (oximetria de pulso para triagem de cardiopatias congênitas críticas): realizado entre 24-48h de vida (idealmente >24h), antes da alta hospitalar. Técnica: oximetria de pulso no membro superior direito (MSD, pré-ductal) e em um membro inferior (MID, pós-ductal). Resultado: normal — SatO2 ≥95% em ambas as medidas E diferença entre MSD e MID ≤3%. Anormal — SatO2 <95% em qualquer medida OU diferença >3% entre MSD e MID. Conduta se anormal: repetir o teste em 1h. Se persistir alterado (2 falhas): ecocardiograma transtorácico com Doppler. Cardiopatias congênitas críticas que o teste detecta: síndrome de hipoplasia de VE, atresia pulmonar com septo íntegro, transposição de grandes artérias, tronco arterioso, tetralogia de Fallot, atresia tricúspide, drenagem anômala total de veias pulmonares. A triagem reduz o risco de morte por choque cardiogênico antes do diagnóstico (diagnóstico clínico perde pois muitos têm sopro ausente, sat normal ao nascimento devido ao canal arterial patente que fecha depois). Falsos positivos: hipertensão pulmonar, doença pulmonar (pneumonia, TTN), infecção neonatal, aspiração meconial. Falsos negativos: coarctação de aorta (pré-ductal normal, pós-ductal pode ser normal se canal patente).",
                tags = listOf("pediatria", "coraçãozinho", "oximetria", "cardiopatia congênita"), citation = "Diretriz SBP 2023 - Triagem de Cardiopatias Congênitas"),
            LibraryContentItem(id = "peds_006", title = "Icterícia neonatal — classificação por horas de vida", category = "CLINICA_MEDICA",
                summary = "Icterícia neonatal: tabela de Bhutani (nomograma) por horas de vida. Zona de alto risco: >percentil 95.",
                content = "Icterícia neonatal (Hiperbilirrubinemia indireta): Fisiologia: hemoglobina fetal → degradação → bilirrubina indireta (que o fígado imaturo não conjuga). Icterícia fisiológica: surge após 24-36h de vida, pico 3-5 dias (RN termo) ou 5-7 dias (RN pré-termo), desaparece em 7-10 dias. Não ultrapassa os limites do nomograma. Icterícia patológica: <24h, ultrapassa nomograma, ↑↑ BT >5 mg/dL/dia, direta >2 mg/dL, >14 dias (prolongada). Causas patológicas: incompatibilidade Rh/ABO, deficiência de G6PD, esferocitose, hemólise, infecção, hematoma, policitemia, síndrome de Crigler-Najjar, colestase (hiperbilirrubina direta). Nomograma de Bhutani (2004): Gráfico que relaciona bilirrubina total (mg/dL) com idade em horas. Linhas: percentil 40 (baixo risco), 75 (intermediário-baixo), 95 (intermediário-alto), e linha de alto risco (>95). Objetivo: guiar fototerapia e exsanguineotransfusão. Quanto mais precoce a icterícia, menor o limite para fototerapia (porque o fígado é mais imaturo e a barreira hematoencefálica é mais permeável). Cuidado com: kernicterus (encefalopatia bilirrubínica — lesão irreversível dos núcleos da base: olhar para cima, rigidez, opistótono, surdez neurossensorial, disfunção motora). Prevenção: fototerapia adequada. Fatores de risco para kernicterus: prematuridade, hipóxia, acidose, hipoalbuminemia, sepse, hemólise.",
                tags = listOf("pediatria", "icterícia", "bilirrubina", "bhutani", "fototerapia"), citation = "Diretriz SBP 2023 - Icterícia Neonatal"),
            LibraryContentItem(id = "peds_007", title = "Fototerapia — indicação conforme bilirrubina total e idade", category = "CLINICA_MEDICA",
                summary = "Fototerapia indicada quando bilirrubina total ultrapassa os limites do nomograma de Bhutani (por horas de vida e fatores de risco).",
                content = "Fototerapia: tratamento da hiperbilirrubinemia indireta (converte bilirrubina em fotoisômeros hidrossolúveis excretáveis na bile e urina). Indicação: baseada no nomograma de Bhutani (por horas de vida, bilirrubina total, peso e fatores de risco). A regra geral simplificada (lembrete, não substitui nomograma): RN termo saudável sem fatores de risco: fototerapia se BT ≥15-18 mg/dL (2º-3º dia). RN de risco (hemólise, asfixia, acidose, hipotermia, hipoalbuminemia, infecção): fototerapia em níveis mais baixos (BT ≥10-13 mg/dL no 1º dia). RN pré-termo (<37 sem): limites menores (ex: 1.500-2.000g → fototerapia se BT ≥12-15 mg/dL dependendo da idade). Implementação: lâmpadas LED (mais eficazes), manter bebê nu (exceto fralda), proteção ocular (máscara escura). Distância da fonte: 30-40 cm. Superfície de exposição máxima (deitar de barriga para baixo, virar de lado). Hidratação oral/IV para compensar perdas insensíveis (pode haver fezes amolecidas, perda hídrica). Duração: até BT abaixo do limite para fototerapia em 2 medições consecutivas (intervalo de 12-24h). Efeitos colaterais: diarreia, desidratação, rash, hipertermia. Contraindicação: hiperbilirrubinemia direta >2 mg/dL (fototerapia pode causar bronze baby syndrome). Se fototerapia falha (BT continua subindo >0,5 mg/dL/h): exsanguineotransfusão.",
                tags = listOf("pediatria", "fototerapia", "icterícia", "bilirrubina"), citation = "Diretriz SBP 2023 - Icterícia Neonatal"),
            LibraryContentItem(id = "peds_008", title = "Exsanguineotransfusão neonatal", category = "CLINICA_MEDICA",
                summary = "Exsanguineotransfusão: quando fototerapia falha ou BT >20-25 mg/dL. Troca duplo volume (170 mL/kg).",
                content = "Exsanguineotransfusão (EXT) neonatal: procedimento de urgência para remover bilirrubina e anticorpos da circulação do RN quando a fototerapia intensiva é insuficiente para reduzir o risco de kernicterus. Indicação: BT >25 mg/dL em RN termo saudável; BT >20 mg/dL em RN com fatores de risco (hemólise isoimune, asfixia, acidose, hipoalbuminemia, sepse, hipotermia); BT >não responsiva à fototerapia (subindo >0,5-1 mg/dL/h). Incremento rápido de BT (>1 mg/dL/h em <6h). Técnica: acesso venoso umbilical (cateter umbilical). Extrair e infundir volumes iguais de sangue reconstituído (concentrado de hemácias O Rh- + plasma fresco compatível). Volume de troca dupla: 170 mL/kg (2 vezes a volemia neonatal ~85 mL/kg). In/out: alíquotas de 5-10 mL/kg (para não alterar volemia). Duração: 45-90 min. Durante o procedimento: monitorizar FC, PA, SatO2, glicemia (risco de hipoglicemia, hipocalcemia). Repor cálcio (gluconato de Ca 100 mg/kg a cada 100 mL trocados). Efeitos colaterais: hipoglicemia (citrato), hipocalcemia, trombocitopenia, neutropenia, arritmia, embolia gasosa, infecção (cateter). Alvo: BT <20-22 mg/dL após EXT. Pode precisar repetir se BT sobe novamente. Se falha: considerar fenobarbital (indutor enzimático), imunoglobulina EV (se isoimune Rh/ABO). Encaminhamento a centro de referência em neonatologia.",
                tags = listOf("pediatria", "exsanguineotransfusão", "icterícia", "kernicterus"), citation = "Diretriz SBP 2023 - Icterícia Neonatal"),
            LibraryContentItem(id = "peds_009", title = "Desconforto respiratório neonatal — surfactante + CPAP", category = "CLINICA_MEDICA",
                summary = "Desconforto respiratório por deficiência de surfactante (SDR). CPAP precoce + surfactante exógeno se necessário.",
                content = "Síndrome do Desconforto Respiratório (SDR, doença de membrana hialina): deficiência de surfactante em RN prematuro (<34 semanas). Quadro progressivo: desconforto respiratório nas primeiras horas de vida (taquipneia, retrações, batimento de asa nasal, gemido expiratório, tiragem intercostal, cianose). RX tórax: infiltrado reticulogranular difuso + broncograma aéreo. Diagnóstico: clínico + radiográfico. Profilaxia: corticoide antenatal (betametasona 12 mg IM 2 doses 24/24h) entre 24-34 semanas (reduz SDR, hemorragia intraventricular, enterocolite necrosante). Tratamento: CPAP nasal precoce: pressão 5-8 cmH2O (mantém alvéolos abertos, reduz atelectasia, estabiliza caixa torácica). A CPAP precoce na sala de parto para RN <32 sem reduz necessidade de surfactante e ventilação. Surfactante exógeno: indicado se FiO2 >0,30-0,40 com CPAP (ou se intubado). Administração: 100-200 mg/kg (por via endotraqueal). Técnica INSURE (Intubar-Surfactante-Extubar para CPAP) ou LISA (Less Invasive Surfactant Administration) — preferível, evita ventilação mecânica. Ventilação mecânica: se CPAP + surfactante falha, usar ventilação protetora (VC 4-6 mL/kg, PEEP 5-7 cmH2O, limitar PIP <25). Cuidados: suporte térmico (incubadora), monitorizar gases, temperatura, glicemia, hidratação. Complicações: pneumotórax, DBP (displasia broncopulmonar), hemorragia intraventricular, PDA (persistência do canal arterial), ROP (retinopatia).",
                tags = listOf("pediatria", "sdra", "surfactante", "cpap", "prematuro"), citation = "Diretriz SBP 2023 - SDR Neonatal"),
            LibraryContentItem(id = "peds_010", title = "Síndrome de aspiração meconial", category = "CLINICA_MEDICA",
                summary = "Aspiração de líquido amniótico meconial. Suporte ventilatório + CPAP + surfactante + óxido nítrico (se hipertensão pulmonar).",
                content = "Síndrome de Aspiração Meconial (SAM): aspiração de líquido amniótico meconial (geralmente em RN pós-termo ou com sofrimento fetal). Fisiopatologia: mecônio obstrui vias aéreas → pneumonite química → inflamação + inativação de surfactante → atelectasia + hipertensão pulmonar. Quadro: RN com líquido meconial espesso, desconforto respiratório nas primeiras horas, hiperinsuflação torácica (tórax em barril), cianose. RX tórax: infiltrados grosseiros irregulares + áreas de hiperinsuflação + atelectasia. Tratamento: na sala de parto, se RN não vigoroso (hipotônico, FR <30, FC <100): intubar e aspirar traqueia (meconial suction). Se RN vigoroso: não aspirar (conduta atual não recomenda). Suporte ventilatório: oxigênio para manter SpO2 >92%. CPAP é controverso (pode hiperinsuflar) — preferir ventilação mecânica se necessário (modo SIMV ou HFOV). Surfactante: 100-200 mg/kg — pode lavar mecônio e reduzir inflamação. Óxido nítrico inalatório (iNO) 5-20 ppm: se hipertensão pulmonar persistente (PPHN) — indicado se gradiente pré-pós ductal (SatO2 >5% entre MSD e MID) ou ecocardiograma com hipertensão pulmonar. Se PPHN refratária: ventilação oscilatória de alta frequência (HFOV), sildenafil, ou ECMO. ATB: se suspeita de pneumonia (hemocultura). Cuidados: hidratação, temperatura, glicemia. Complicações: pneumotórax, hipertensão pulmonar, encefalopatia hipóxico-isquêmica, persistência de canal. Mortalidade: 5-10%. A prevenção (evitar pós-termo, monitorização fetal) reduziu incidência.",
                tags = listOf("pediatria", "aspiração meconial", "samb", "óxido nítrico"), citation = "Diretriz SBP 2023 - Aspiração Meconial"),
            LibraryContentItem(id = "peds_011", title = "Doença hemolítica do RN (incompatibilidade Rh)", category = "CLINICA_MEDICA",
                summary = "Prevenção com imunoglobulina anti-D em 28 sem e pós-parto (se RN Rh+). Tratamento: fototerapia ± imunoglobulina ± exsanguineotransfusão.",
                content = "Doença Hemolítica do Recém-Nascido (DHRN) por incompatibilidade Rh: mãe Rh-, pai Rh+, RN Rh+. A mãe produz anticorpos anti-D (por sensibilização em gestação anterior ou hemorragia feto-materna) → atravessam placenta e hemolisam hemácias do RN. Quadro: icterícia precoce (<24h), anemia hemolítica progressiva, hidropsia fetal (anasarca, ascite, insuficiência cardíaca — forma grave). Diagnóstico: Coombs direto positivo no RN, anemia, reticulocitose, bilirrubina indireta elevada. Teste de Kleihauer-Betke (nas mães Rh-) para quantificar hemorragia feto-materna. Prevenção: Imunoglobulina anti-D (RhoGAM) 300 mcg IM: em todas as gestantes Rh- não sensibilizadas na 28ª semana. Também: pós-parto (se RN Rh+, dentro de 72h), pós-abortamento, pós-hemorragia, pós-procedimentos invasivos (amniocentese, biópsia de vilo corial, cordocentese). A profilaxia reduz a sensibilização de >15% para <1%. Tratamento do RN: fototerapia intensiva + imunoglobulina EV (1g/kg em 2-4h) + exsanguineotransfusão se necessário. Foi uma das maiores conquistas da medicina perinatal: reduziu a hidropsia e a mortalidade em mais de 90%. Incompatibilidade ABO: mais comum mas geralmente mais leve (icterícia precoce, Coombs direto pode ser +, esferócitos). Tratamento: fototerapia. A incompatibilidade ABO não tem prevenção. Todas as gestantes devem ter tipagem Rh + teste de Coombs indireto no 1º trimestre. Se Coombs indireto positivo, acompanhar com titulação de anticorpos (a cada 2-4 sem). Se título ≥1:16: US Doppler da artéria cerebral média (ACM) para avaliar anemia fetal. Se ACM PSV >1,5 MoM: cordocentese + transfusão intrauterina se anemia fetal grave.",
                tags = listOf("pediatria", "doença hemolítica", "rh", "anti-d", "imunoglobulina"), citation = "Diretriz SBP 2023 - Incompatibilidade Rh"),
            LibraryContentItem(id = "peds_012", title = "Aleitamento materno — contraindicações", category = "CLINICA_MEDICA",
                summary = "Contraindicações absolutas: HIV, HTLV. Hepatite B NÃO contraindica (pode amamentar com vacina + imunoglobulina).",
                content = "Aleitamento materno — contraindicações: Absolutas (NÃO PODE amamentar): HIV — transmissão pelo leite materno. HTLV-1 e HTLV-2 — risco de transmissão de linfoma/leucemia de células T e mielopatia associada ao HTLV. Galactosemia clássica — erro inato do metabolismo (deficiência de GALT). Uso de drogas de abuso (cocaína, heroína, anfetaminas) — exceto metadona em programa de desintoxicação estável. Quimioterapia antineoplásica. Radioterapia com iodo-131 (se iodada, suspender por 2-4 semanas). Alguns medicamentos (ex: lítio, amiodarona, anti-tireoidianos em altas doses? — avaliar risco-benefício). Relativas (pode amamentar com cuidados): Hepatite B — NÃO contraindica! RN recebe vacina + imunoglobulina anti-HB na sala de parto e pode amamentar (risco zero com profilaxia). Hepatite C (HCV) — NÃO contraindica (não há evidência de transmissão pelo leite, exceto se fissura mamilar sangrante). Citomegalovírus (CMV) — suspender apenas em RN <32 semanas ou <1.500g (prematuro extremo) — leite pode ser pasteurizado (Holder: 62,5°C por 30 min). Tuberculose — suspender até 2 semanas após início do tratamento da mãe (se BK+). Varicela — se mãe teve nos 5 dias antes a 2 dias após o parto: separar RN, dar imunoglobulina (VariZIG), pode retornar aleitamento quando não houver mais lesão infecciosa. Herpes — suspender se lesão ativa na mama. Dengue e Zika: podem amamentar. Covid-19: pode amamentar com máscara e higiene. Mastite: NÃO suspender! Esvaziar a mama (ordenha) — o leite é seguro. Além disso, o leite materno é o alimento ideal nos primeiros 6 meses de vida exclusivo, continuado até 2 anos ou mais com alimentos complementares.",
                tags = listOf("pediatria", "aleitamento", "hiv", "htlv", "hepatite b"), citation = "Diretriz SBP 2023 - Aleitamento Materno"),
            LibraryContentItem(id = "peds_013", title = "Cólica do lactente — manejo", category = "CLINICA_MEDICA",
                summary = "Cólica do lactente: choro >3h/dia, >3 dias/sem, >3 sem. Manejo: orientação, lactase, simeticona, mudanças na dieta materna.",
                content = "Cólica do lactente (3 meses de cólica): definição de Wessel (1954, revisada): choro e/ou irritabilidade em lactente saudável e bem nutrido, por >3 horas/dia, >3 dias/semana, >3 semanas. Início: 2ª-4ª semanas, pico 6 semanas, resolve até 3-4 meses. Quadro: choro intenso, inconsolável, pernas flexionadas, punhos cerrados, face ruborizada, geralmente no final da tarde/noite. Entre crises, lactente normal. Fisiopatologia: desconhecida (imaturidade do SNC, imaturidade intestinal, disbiose, excesso de gás, alergia à proteína do leite de vaca — APLV? Isto é uma minoria dos casos). Manejo: orientação aos pais (educar sobre o quadro benigno e autolimitado, não é doença, não é culpa deles). Reduzir estresse materno. Simeticona (Luftal, Milicon) 2,5-5 mg/kg 6/6h (evidência fraca). Lactase (SIG Enzimas) para lactentes com suspeita de intolerância à lactose (20% podem melhorar). Chá de camomila/erva-doce (1-2 mL/kg/dia, a partir de 2 meses) — pode melhorar. Probióticos (Lactobacillus reuteri) 10⁸ UFC/dia — reduz tempo de choro. Se APLV suspeita (cólica + eczema, sangue nas fezes, vômitos): mãe que amamenta → dieta sem leite de vaca e derivados por 2-4 sem. Fórmula infantil → trocar para fórmula extensamente hidrolisada (Neocate, Alfaré) por 2-4 sem. Não dar remédios (anticolinérgicos, álcool?, laxantes). Massagem, banho morno. Não sacudir o bebê (conscientizar sobre síndrome do bebê sacudido — shaken baby syndrome).",
                tags = listOf("pediatria", "cólica", "lactente", "simeticona", "probiótico"), citation = "Diretriz SBP 2023 - Cólica do Lactente"),
            LibraryContentItem(id = "peds_014", title = "Desidratação em criança — planos A, B, C", category = "CLINICA_MEDICA",
                summary = "Plano A (TRO), Plano B (sonda nasogástrica), Plano C (venosa). OMS classifica: sem desidratação, alguma, grave.",
                content = "Desidratação em crianças — classificação OMS: Sem desidratação (<5%): olhos normais, mucosa oral úmida, bebe normalmente, sinal da prega <1s. Plano A: Tratamento em casa com TRO (solução de reidratação oral — SRO) 50-100 mL para cada evacuação diarreica ou vômito. Manter alimentação. Alguma desidratação (5-10%): olhos fundos, mucosa oral seca, bebe avidamente/sedento, sinal da prega 1-2s. Plano B: SRO via sonda nasogástrica (SNG) em ambiente de observação: 50-100 mL/kg VO/SNG em 4 horas (pequenos volumes frequentes). Reavaliar a cada 15-30 min. Se vômito: tentar novamente após 10-15 min. Se recusar SRO: SNG. Desidratação grave (>10%): letargia/coma, olhos muito fundos, mucosa seca, não bebe, sinal da prega >2s. Plano C: Acesso venoso + Ringer lactato (ou SF 0,9%) 30 mL/kg na primeira 1h (crianças: 20 mL/kg em 30 min, repetir se necessário). <1 ano: 30 mL/kg na 1ª hora, depois 70 mL/kg nas 5h seguintes. >1 ano: 30 mL/kg na 1ª hora, depois 70 mL/kg nas 2,5h seguintes. Alimentação: retornar assim que desidratação corrigida. Não suspender aleitamento materno. Para crianças com diarreia aguda e alguma desidratação: suplementar ZINCO (10 mg/dia <6 meses, 20 mg/dia >6 meses por 10-14 dias) — reduz duração e gravidade da diarreia. Sinais de alerta: letargia, vômitos incoercíveis, sangue nas fezes, sinais de infecção grave, desnutrição grave, <2 meses.",
                tags = listOf("pediatria", "desidratação", "plano a b c", "tro"), citation = "Diretriz OMS 2023 - Diarreia Aguda"),
            LibraryContentItem(id = "peds_015", title = "Solução de reidratação oral (SRO) — osmolaridade", category = "CLINICA_MEDICA",
                summary = "SRO OMS: osmolaridade 245-260 mOsm/L, sódio 75 mEq/L, glicose 75 mmol/L. Preparo: 2 colheres de açúcar + 1 pitada de sal em 1L de água.",
                content = "Solução de Reidratação Oral (SRO) — OMS: Composição (por litro): glicose 75 mmol (13,5 g), sódio 75 mEq, potássio 20 mEq, cloro 65 mEq, citrato 10 mmol, osmolaridade 245 mOsm/L. Como preparar: 2 colheres (sopa) de açúcar (20g) + 1 colher (café) de sal (3,5g) em 1 litro de água filtrada (fórmula caseira se não houver SRO industrializada). A SRO industrializada (sachê) é preferível (osmolaridade e concentração corretas). A SRO reduziu a mortalidade por diarreia de 5 milhões/ano para <2 milhões. Princípio: sódio e glicose são co-transportados no enterócito (SGLT-1) → água é absorvida osmoticamente. A SRO funciona mesmo se houver secreção ativa de água (cólera). Administração: crianças com diarreia aguda e sem desidratação: dar SRO após cada evacuação (50-100 mL para crianças <2 anos, 100-200 mL para >2 anos). Com alguma desidratação (plano B): 50-100 mL/kg nas primeiras 4h, fracionado (colher de chá a cada 1-2 min). Se a criança vomitar, esperar 10 min e oferecer novamente. Congelar em cubos de gelo pode ajudar. Contraindicação: íleo paralítico (distensão abdominal, ruídos hidroaéreos ausentes). Solução oral reidratante de baixa osmolaridade (SRO-BO): 20-50% menos vômito que SRO padrão, eficácia igual. A SRO é segura e não deve ser retida (se administrada corretamente). Manter aleitamento materno durante TRO. Oferecer SRO entre as mamadas.",
                tags = listOf("pediatria", "sro", "reidratação", "diarreia"), citation = "Diretriz OMS 2023 - Diarreia Aguda"),
            LibraryContentItem(id = "peds_016", title = "Pneumonia em criança — tratamento ambulatorial", category = "CLINICA_MEDICA",
                summary = "Amoxicilina 50 mg/kg/dia por 7 dias para pneumonia comunitária não complicada em crianças ambulatoriais.",
                content = "Pneumonia na infância — tratamento: agente: S. pneumoniae é a principal causa bacteriana (pré-pandemia). Vírus (VSR, influenza, parainfluenza, adenovírus) e Mycoplasma pneumoniae conforme faixa etária. Lactentes 3 m-5 anos: pneumococo (principal) + vírus. >5 anos: Mycoplasma pneumoniae + pneumococo. Diagnóstico: febre + tosse + taquipneia (FR >40 <12 meses, >30 1-5 anos, >20 >5 anos). Associado: sibilos (vírus), estertores, tiragem subcostal. RX tórax: infiltrado, consolidação (não rotina). Tratamento ambulatorial: pneumonia comunitária não complicada: Amoxicilina 50 mg/kg/dia VO (dividido 8/8h) por 7 dias. Se suspeita de Mycoplasma (>5 anos, tosse seca, febre baixa, cefaleia, sintomas extrarrespiratórios): macrolídeo (azitromicina 10 mg/kg/dia por 5 dias). Alergia à penicilina: claritromicina (15 mg/kg/dia 12/12h por 7 dias), ou levofloxacino (em crianças maiores). Pneumonia viral (leve, sibilos, início gradual, febre): suporte (oxigênio se hipoxemia, hidratação), não usar ATB. Critérios de internação: <3 meses, FR >60 <6 meses, sinais de desconforto respiratório grave (retrações, batimento de asa nasal, gemido), SpO2 <92%, cianose, recusa alimentar (desidratação), convulsão, apneia, toxemia, complicações (derrame, pneumotórax), doença de base (prematuridade, cardiopatia, pneumopatia). Acompanhamento: reavaliação em 48-72h (se não melhora, pensar em resistência, complicações ou ATB incompleto). A vacina pneumocócica 10-valente (PCV10) reduziu pneumonia em <20% das hospitalizações.",
                tags = listOf("pediatria", "pneumonia", "amoxicilina", "criança"), citation = "Diretriz SBP 2023 - Pneumonia na Infância"),
            LibraryContentItem(id = "peds_017", title = "Pneumonia grave em criança — internação", category = "CLINICA_MEDICA",
                summary = "Pneumonia grave: internação + ampicilina e gentamicina (ou ceftriaxona) + oxigênio.",
                content = "Pneumonia grave na infância (critérios OMS): taquipneia com tiragem subcostal, SpO2 <92%, cianose, incapacidade de beber, convulsão, letargia, gemido expiratório. RN e <3 meses: sempre internar. Tratamento hospitalar: Oxigênio: cateter nasal (0,5-2 L/min) ou máscara (5 L/min) para SpO2 >92%. Antibiótico: <3 meses — ampicilina (150-200 mg/kg/dia 6/6h) + gentamicina (5-7,5 mg/kg/dia 1x/dia) ou ceftriaxona (50-100 mg/kg/dia 12/12h). 3 meses-5 anos — ampicilina/penicilina cristalina (200.000 UI/kg/dia 6/6h) ± gentamicina se <1 ano ou sepse. >5 anos — ceftriaxona (50-100 mg/kg/dia) + macrolídeo (se Mycoplasma). Complicações: derrame pleural/empiema — toracocentese + drenagem tubular (se empiema franco). ATB EV por 7-10 dias. Trocar para VO após melhora clínica (2-3 dias). Duração total: 7-14 dias. Hemocultura, proteína-C reativa (PCR), hemograma (leucocitose). US torácico: avalia derrame. Se refratário (sem melhora em 48-72h): pensar em resistência (pneumococo resistente, S. aureus, Gram-negativo), complicação (empiema, abscesso pulmonar), ou outra causa (viral, tuberculose, aspiração de corpo estranho). Vacinação: pneumocócica (PCV10/13) + H. influenzae tipo b (Hib) reduziram drasticamente pneumonia grave em crianças.",
                tags = listOf("pediatria", "pneumonia grave", "internação", "ampicilina", "gentamicina"), citation = "Diretriz SBP 2023 - Pneumonia na Infância"),
            LibraryContentItem(id = "peds_018", title = "Bronquiolite viral (VSR) — tratamento de suporte", category = "CLINICA_MEDICA",
                summary = "Suporte com oxigênio, hidratação, aspiração de vias aéreas. Não usar broncodilatador rotineiramente (apenas se teste terapêutico positivo).",
                content = "Bronquiolite viral aguda: infecção respiratória viral mais comum em <2 anos (pico 3-6 meses). Agente: Vírus Sincicial Respiratório (VSR) — 70-80%. Quadro: início com coriza + febre baixa → piora respiratória 3-5 dias: taquipneia, sibilos, esforço respiratório, tosse paroxística. Oximetria <92% indica hipoxemia. FR >70bpm indica risco de falência respiratória. Fatores de risco para gravidade: prematuridade <32 sem, DBP, cardiopatia congênita, imunodeficiência, idade <3 meses. Diagnóstico: clínico! RX tórax (opcional) — hiperinsuflação, atelectasia, espessamento peribrônquico. Teste rápido para VSR (swab nasal) — identifica o vírus. Tratamento: Suporte: oxigênio se SpO2 <92% (cateter nasal, máscara de Venturi) . Hidratação: TRO (se esforço respiratório leve), sonda nasogástrica (se recusar ou moderado), ou EV se grave. Desobstrução nasal: aspiração de muco (soro fisiológico + bombinha) antes das mamadas. Fisioterapia respiratória: controversa (evitar vibração, drenagem postural, tapotagem — piora obstrução). Broncodilatador (salbutamol neb/jato) — NÃO recomendado na bronquiolite (evidência fraca, sem benefício na maioria). Fazer teste terapêutico: 1 dose de salbutamol, reavaliar 15 min após: se melhora clínica (↓ trabalho respiratório) → manter 6/6h. Se não melhorar → suspender. Corticoide (prednisolona) — NÃO usar (sem benefício, exceto primeira crise de sibilos com história familiar de asma?). Adrenalina nebulizada — pode ser usada no PS (reduz trabalho respiratório agudo) mas não reduz hospitalização ou readmissão. Antiviral (ribavirina) — apenas em prematuras graves e imunocomprometidos. Profilaxia: palivizumabe (Synagis) 15 mg/kg IM/mês (5 doses) durante o inverno para: <29 sem e <12 meses, DBP com O2 <12 meses, cardiopatia congênita hemodinamicamente significativa. Cuidados de suporte são a base do tratamento.",
                tags = listOf("pediatria", "bronquiolite", "vsr", "suporte"), citation = "Diretriz SBP 2023 - Bronquiolite"),
            LibraryContentItem(id = "peds_019", title = "Laringotraqueíte (crupe) — tratamento", category = "CLINICA_MEDICA",
                summary = "Corticoide (dexametasona 0,15-0,6 mg/kg VO/IM) + adrenalina nebulizada (0,5 mL/kg) se grave.",
                content = "Laringotraqueíte (Crupe): síndrome obstrutiva da glote/subglote, geralmente viral (parainfluenza tipo 1). Faixa etária: 6 meses - 3 anos (pico 18 meses). Quadro: tosse ladrante (cachorro), rouquidão, estridor inspiratório, desconforto respiratório. Tipicamente piora à noite. Sintomas prévios de IVAS (coriza, tosse, febre). Diagnóstico: clínico! Exames desnecessários na maioria. RX de pescoço (AP): sinal da torre/steeple (estreitamento subglótico) — opcional, para descartar epiglotite. Classificação de gravidade (Westley Score): Leve (1-3): estridor em repouso? tosse ladrante? sem tiragem. Moderada (4-6): estridor em repouso + tiragem leve. Grave (7-11): estridor em repouso + tiragem acentuada + agitação/letargia + cianose. Tratamento: Leve/Moderada: dexametasona 0,15-0,6 mg/kg VO ou IM dose única (máx 12 mg). Início de ação 4-6h, duração 48h. Reduz admissão hospitalar em 50%. Moderada-Grave: dexametasona + adrenalina nebulizada (L-adrenalina 1:1.000: 0,5 mL/kg diluída em 2 mL de SF, máx 5 mL). Ação rápida (10 min), duração 1-2h. Melhora sintomas. Pode repetir a cada 2-4h. Prednisona/prednisolona (1-2 mg/kg/dia) por 3-5 dias (alternativa). Internação: se escore >4, desconforto respiratório grave, cianose, SpO2 <92%, <3 meses, ou após adrenalina sem melhora por >2h. UTI: se grave (extubação iminente), intubação orotraqueal. Tubo 0,5-1mm menor que o esperado para a idade. Epiglotite (diferencial): febre alta, disfagia, sialorreia, posição tripé, sem tosse. Hemófilo influenzae tipo b (Hib), intubação imediata, em ambiente controlado. Crupe espasmódico: sem febre, alérgico, responde bem a adrenalina.",
                tags = listOf("pediatria", "crupe", "laringotraqueíte", "dexametasona", "adrenalina"), citation = "Diretriz SBP 2023 - Laringotraqueíte"),
            LibraryContentItem(id = "peds_020", title = "Epiglotite — intubação precoce", category = "CLINICA_MEDICA",
                summary = "Epiglotite: febre alta + disfagia + sialorreia + posição tripé. Intubação imediata em centro cirúrgico. ATB ceftriaxona.",
                content = "Epiglotite (supraglotite): infecção bacteriana (Haemophilus influenzae tipo b) da epiglote e estruturas supraglóticas. Rara na era pós-vacina Hib. Agora pode ser causada por S. pyogenes, S. pneumoniae e S. aureus. Faixa etária: 2-7 anos (mas também adultos). Quadro clínico CLÁSSICO: início agudo (<12h), febre alta (39-40°C), disfagia intensa (dificuldade de engolir até saliva), sialorreia (baba), voz anasalada/hipernasal (voz de batata quente), tosse não ladrante, posição tripé (sentado, para frente, boca aberta). Sem estridor audível até obstrução quase completa. A criança NÃO deve ser deitada (piora obstrução). Diagnóstico (clínico — não mexer na orofaringe!). Não usar abaixador de língua (risco de laringoespasmo e PCR). Levar ao centro cirúrgico preparado para via aérea difícil. Raio-X de pescoço perfil: sinal do polegar (epiglote edemaciada) — se disponível, mas não retardar tratamento. Conduta: Intubação orotraqueal em centro cirúrgico (anestesia geral), por cirurgião pediátrico/otorrino (via aérea difícil). Hemoculturas. ATB IV: ceftriaxona 50-100 mg/kg/dia 12/12h por 7-10 dias. Se alergia, cloranfenicol. Após intubação, extubação em 24-48h (quando houver escape de ar ao redor do tubo). A epiglotite tem curso rápido e imprevisível — não hesitar em intubar! Vigilância: a profilaxia com vacina Hib (aos 2, 4 e 6 meses) reduziu epiglotite em >95%. A vacina Hib está no calendário SUS.",
                tags = listOf("pediatria", "epiglotite", "intubação", "ceftriaxona"), citation = "Diretriz SBP 2023 - Epiglotite"),
            LibraryContentItem(id = "peds_021", title = "Meningite bacteriana em crianças — tratamento", category = "CLINICA_MEDICA",
                summary = "Ceftriaxona + vancomicina + dexametasona (se suspeita pneumococo). Duração 7-21 dias.",
                content = "Meningite bacteriana em crianças: Agentes por faixa etária: RN (<3 meses): Streptococcus agalactiae (GBS), E. coli, Listeria monocytogenes → ampicilina + cefotaxima (ou gentamicina) + aciclovir (se herpes). Lactentes (3 meses - 5 anos): S. pneumoniae, N. meningitidis, H. influenzae tipo b (Hib — raro com vacina) → ceftriaxona (100 mg/kg/dia 12/12h) + vancomicina (60 mg/kg/dia 6/6h). >5 anos: N. meningitidis, S. pneumoniae → ceftriaxona + vancomicina. Dexametasona (0,15 mg/kg 6/6h por 2-4 dias): reduz perda auditiva em meningite por H. influenzae e pnermococo. Administrar antes ou junto com o ATB (não após). Punção lombar (PL): padrão ouro para diagnóstico. Coleta: LCR para bioquímica (glicose, proteína), cultura, Gram, PCR (meningococo, pneumococo, Hib, Listeria). Gram: diplococos Gram+ (pneumococo), Gram- (meningococo), bacilos Gram+ (Listeria). Bioquímica: glicose <40 (ou relação LCR/sangue <0,4), proteína >100, leucócitos >1.000 com predomínio neutrófilos. TC de crânio antes da PL se: sinais de hipertensão intracraniana, deficit neurológico focal, papiledema, imunossupressão. Duração da ATB: meningococo 5-7 dias, pneumococo 10-14 dias, H. influenzae 7-10 dias, GBS 14-21 dias, Listeria ≥21 dias. Acompanhamento: hemocultura, provas de fase aguda. Profilaxia para contactantes: rifampicina (se meningococo/hib). Notificação obrigatória. Prognóstico: pneumococo: mortalidade 10-15% (sequelas 30%). Meningococo: mortalidade 5-10% (reduzida com tratamento precoce).",
                tags = listOf("pediatria", "meningite bacteriana", "ceftriaxona", "vancomicina"), citation = "Diretriz SBP 2023 - Meningite Bacteriana"),
            LibraryContentItem(id = "peds_022", title = "Febre em criança — risco de infecção bacteriana grave", category = "CLINICA_MEDICA",
                summary = "Critérios de Rochester ou Yale para risco de infecção bacteriana grave em crianças febris <3 meses.",
                content = "Febre em crianças <3 meses (lactentes jovens): Avaliar risco de infecção bacteriana grave (IBG — sepse, meningite, ITU, pneumonia, artrite séptica, osteomielite, enterite bacteriana). Critérios de Rochester (alto valor preditivo para excluir IBG): Baixo risco se TODOS: 1) Nascido a termo (>37 sem). 2) Sem hospitalização no período neonatal. 3) Sem ATB prévio. 4) Sem icterícia inexplicada. 5) Sendo amamentado (ou fórmula). 6) Sem foco infeccioso ao exame. 7) Exames: leucócitos 5.000-15.000, bastões <1.500, piúria <10/campo, fezes sem leucócitos (se diarreia). Baixo risco + bom estado geral: acompanhamento ambulatorial (mãe confiável, retorno em 24h). Alto risco: internação + propedêutica (hemocultura, sumário de urina + urocultura, PL, RX tórax se sintomas respiratórios, fezes se diarreia) + ATB empírico (ampicilina + ceftriaxona/gentamicina). Critérios de Yale (aplicar a crianças 3-36 meses): Observação clínica (6 parâmetros: nível de consciência, choro, tônus, interação, conforto, hidratação). Se escore >10 = 10% de IBG. Estados tóxicos Yale >16 = 25% de IBG. Crianças febris 3-36 meses sem foco, com boa vacinação e sem sinais tóxicos: investigar ITU (sumário + urocultura). Febre sem sinais localizatórios >39°C em 3-36 meses: considerar ITU (10% das meninas, 3% dos meninos). Se piúria no sumário: urocultura + ATB. Após 36 meses, febre de curta duração e sem foco: exames complementares raramente úteis. A febre é um bom sinal prognóstico na criança (resposta imune ativa).",
                tags = listOf("pediatria", "febre", "rochester", "ivasa", "lactente"), citation = "Diretriz SBP 2023 - Febre em Lactentes"),
            LibraryContentItem(id = "peds_023", title = "Convulsão febril — simples vs complexa", category = "CLINICA_MEDICA",
                summary = "Convulsão febril simples (<15 min, generalizada, 1 em 24h). Complexa (>15 min, focal, >1 em 24h). Manejo com diazepam.",
                content = "Convulsão febril (CF): crise convulsiva em crianças de 6 meses - 5 anos, associada a febre ≥38°C, sem infecção do SNC. Simples (85%): <15 min, generalizada (tônico-clônica), 1 crise em 24h, sem déficit neurológico pós-ictal. Complexa: >15 min, focal, >1 crise em 24h, ou déficit neurológico pós-ictal. Risco de recorrência: 30% (maior em <12 meses). Risco de epilepsia futura: CF simples ≈ 1-2% (sem aumento do risco), CF complexa ≈ 5-10% (aumento do risco). Tratamento da crise aguda (>5 min): diazepam retal (0,5 mg/kg) ou midazolam bucal/nasal (0,2 mg/kg). Se persiste >5-10 min após BZD: chamar emergência. Diazepam IV se acesso venoso: 0,3-0,5 mg/kg. Profilaxia antitérmica: uso de antitérmico (paracetamol, ibuprofeno) não reduz recorrência de CF (febre não é o gatilho principal, mas um limiar). Profilaxia anticonvulsivante: NUNCA indicada na CF simples. CF complexa (recorrente ou >15 min): diazepam oral 0,3-0,5 mg/kg/dia durante febre (cada 8h por 2-3 dias). Vale a pena se >4 crises/ano. Se CF muito prolongada (>30 min) = estado de mal epiléptico febril → tratar como estado de mal (fenitoína 20 mg/kg IV). PL: controverso. Considerar PL se: <6 meses (meningite bacteriana pode ser a causa da febre e convulsão), CF complexa (mas risco baixo), ou sinais de irritação meníngea (rigidez nuca, Kernig, Brudzinski). A CF simples não costuma necessitar de exames caros. Explicar aos pais o caráter benigno (não deixa sequelas, não causa epilepsia). Aprender a lidar em casa: deitar de lado, nunca colocar colher/objeto na boca.",
                tags = listOf("pediatria", "convulsão febril", "diazepam", "criança"), citation = "Diretriz SBP 2023 - Convulsão Febril"),
            LibraryContentItem(id = "peds_024", title = "Otite média aguda — critérios e tratamento", category = "CLINICA_MEDICA",
                summary = "Otite média aguda: início agudo + efusão no ouvido médio + otalgia/febre. Amoxicilina 50 mg/kg/dia por 7-10 dias.",
                content = "Otite Média Aguda (OMA): infecção do ouvido médio — principal causa de prescrição de ATB para crianças. Faixa etária: 6-24 meses (pico). Agentes: S. pneumoniae, H. influenzae não tipável, M. catarrhalis (este último cada vez mais frequente). Diagnóstico: critérios: 1) Início agudo (dor ou febre). 2) Efusão no ouvido médio (abaulamento, otorreia, diminuição da mobilidade timpânica — otoscopia pneumática). 3) Sinais de inflamação (otalgia, hiperemia/abaloamento timpânico). Tratamento: 1ª linha: amoxicilina 50 mg/kg/dia VO 8/8h por 7 dias (crianças <2 anos) ou 5 dias (≥2 anos). Se falha após 48-72h: amoxicilina-clavulanato (90/6,4 mg/kg/dia em 2 doses). Alergia à penicilina: azitromicina 10 mg/kg/dia por 3-5 dias, ou cefuroxima 30 mg/kg/dia. Se falha de tratamento, ou complicação (mastoidite, supuração): timpanocentese + cultura. ATB tópico (ciprofloxacino/dexametasona) apenas se otorreia por tubo de ventilação. Observação vigil (watchful waiting) por 48-72h: em crianças >2 anos, OMA unilateral, sem otalgia intensa, sem febre, sem doença de base (antes de iniciar ATB). Controle da dor: ibuprofeno 10 mg/kg 8/8h, paracetamol 15 mg/kg 6/6h. Complicações: mastoidite aguda, paralisia facial, trombose de seio sigmoide, abscesso cerebral. Prevenção: vacina pneumocócica (PCV10/13) + vacina influenza anualmente. Aleitamento materno. Evitar exposição ao tabagismo passivo e creches (2-3 crianças por cuidador ajuda).",
                tags = listOf("pediatria", "otite", "média", "amoxicilina"), citation = "Diretriz SBP 2023 - OMA"),
            LibraryContentItem(id = "peds_025", title = "Faringoamigdalite bacteriana — critérios de Centor", category = "CLINICA_MEDICA",
                summary = "Critérios de Centor: febre >38°C, exsudato amigdaliano, adenomegalia cervical anterior, ausência de tosse. Centor ≥3-4: tratar com penicilina ou amoxicilina.",
                content = "Faringoamigdalite bacteriana (Streptococcus pyogenes, GAS — estreptococo do grupo A): faixa etária: 3-15 anos. Critérios de Centor/McIsaac (modificado por idade) para estimar risco e guiar teste rápido: febre >38°C (1pt), exsudato amigdaliano (1pt), adenomegalia cervical anterior dolorosa (1pt), ausência de tosse (1pt). Idade: 3-14 anos (0pts), 15-44 anos (-1pt), >45 anos (-2pts). Escore: 3-4 → risco 50-60% → testar (teste rápido de estreptococo) ou tratar diretamente (se não disponível). 1-2 → risco 10-20% → testar e tratar se positivo. ≤0 → risco <5% → não testar nem tratar (viral). Tratamento (escolha): Penicilina G benzatina 600.000-1.200.000 UI IM dose única (se baixa adesão). OU Amoxicilina 50 mg/kg/dia VO por 10 dias (aceitação melhor, eficácia similar). Alternativa: fenoximetilpenicilina 250-500 mg 12/12h por 10 dias. Alergia à penicilina: azitromicina 12 mg/kg/dia por 5 dias. Efeito do tratamento: reduz sintomas em 24-36h, previne febre reumática (primordial!), reduz transmissibilidade (24h após início). Início do tratamento pode ser tardio (até 9 dias) e ainda prevenir FR. Portadores assintomáticos: não tratar. Complicações supurativas: abscesso periamigdaliano, cervical, celulite. Complicações não supurativas: febre reumática (cardite, coreia, artrite), glomerulonefrite pós-estreptocócica. A glomerulonefrite NÃO é prevenível por tratamento da faringoamigdalite. Diagnóstico diferencial: mononucleose infecciosa (EBV) — adenomegalia + esplenomegalia, linfocitose com linfócitos atípicos, sorologia IgM-VCA. Amigdalite viral não supurativa: coriza, tosse, rouquidão, conjuntivite, diarreia, exantema. Suporte com sintomáticos.",
                tags = listOf("pediatria", "faringoamigdalite", "centor", "penicilina"), citation = "Diretriz SBP 2023 - Faringoamigdalite"),
            LibraryContentItem(id = "peds_026", title = "Cardiopatia congênita cianótica — tetralogia de Fallot", category = "CLINICA_MEDICA",
                summary = "Tetralogia de Fallot: 4 componentes: CIV, estenose pulmonar, dextraposição da aorta, hipertrofia VD. Tratamento: cirurgia corretiva (primeiro ano).",
                content = "Tetralogia de Fallot (TOF): cardiopatia congênita cianótica mais comum (10% das CC). 4 componentes: 1) Comunicação interventricular (CIV) grande. 2) Estenose pulmonar (infundibular + valvar). 3) Dextraposição da aorta (cavalgamento >50%). 4) Hipertrofia do ventrículo direito (secundária). Quadro: cianose (primeiras semanas a meses), sopro sistólico paraesternal esquerdo (estenose pulmonar), hipodesenvolvimento, crises hipercianóticas (Tet spells): cianose súbita, hiperpneia, taquicardia, síncope. Gatilho: choro, fezes, alimentação → ↓ FC periférica → ↑ shunt D→E → mais cianose. Diagnóstico: Ecocardiograma com Doppler confirma. Rx: coração em bota (ponta elevada, área pulmonar escavada). Tratamento: Cirurgia corretiva (com CEC) no 1º ano de vida (3-12 meses) — patch da CIV + ampliação da via de saída do VD (infundibulotomia/valvotomia). Antes: manter canal arterial patente (PGE1) em neonatos com crises graves, se cianose extremas e saturação não melhora com cirurgia paliativa (shunt de Blalock-Taussig modificado). Tratamento das crises hipercianóticas: posição genupeitoral (ajoelhado, peito nos joelhos) — ↑ RVP, morfina 0,1 mg/kg SC/IM, oxigênio, propranolol 0,1-1 mg/kg (↓ espasmo infundibular), volume IV (se anemia), bicarbonato (se acidose), vasopressores (fenilefrina 5-10 mcg/kg) para ↑ RVP, reduzir shunt D→E. Se refratário, intubação e ventilação. Prognóstico: >90% sobrevivem após cirurgia corretiva. Seguimento: cardiológico, risco de arritmias, regurgitação pulmonar, disfunção VD. Endocardite infecciosa: profilaxia antes de procedimentos dentários/cirurgias (apenas para TOF corrigida com conduto valvulado/alogenia). A TOF é a cardiopatia cianótica que pode chegar à idade adulta sem cirurgia (raro).",
                tags = listOf("pediatria", "tetralogia fallot", "cardiopatia", "cianótica"), citation = "Diretriz SBP 2023 - Cardiopatia Congênita"),
            LibraryContentItem(id = "peds_027", title = "Cardiopatia congênita acianótica — CIA, CIV, PCA", category = "CLINICA_MEDICA",
                summary = "CIA, CIV, PCA: shunts D→E. Fechamento cirúrgico ou percutâneo se hipertensão pulmonar ou ICC.",
                content = "Cardiopatias Congênitas Acianóticas com shunt D→E: Comunicação Interatrial (CIA): deficiência do septo interatrial. Mais comum em meninas, <5% de CC. Diagnóstico: sopro mesossistólico no 2º EIC (foco pulmonar), desdobramento fixo de B2 (expiração → não se fecha). ECG: BRD. Rx: cardiomegalia + hiperfluxo pulmonar. Fechamento: se CIA >5mm, com sobrecarga de VD, aos 2-5 anos. Fechamento percutâneo (prótese) é preferível. Se CIA pequena (<5mm): benigna, não fecha? pode fechar espontaneamente até 1-2 anos. Comunicação Interventricular (CIV): mais comum (30-40% das CC). Sopro holossistólico (regurgitante) paraesternal esquerdo baixo. Quadro: CIV pequena (restritiva) → assintomática, sopro ruidoso, baixo risco. CIV grande (não restritiva) → IC aos 2-4 meses, taquipneia, má alimentação, hipodesenvolvimento, infecções de repetição, hipertensão pulmonar (risco da doença vascular pulmonar). Fechamento: se CIV grande, aos 3-6 meses antes de hipertensão pulmonar). Cirurgia (patch) ou percutânea? Raramente fecha espontaneamente (apenas CIV pequena, muscular). Persistência do Canal Arterial (PCA): vaso entre a aorta e a artéria pulmonar. Mais comum em prematuros. Sopro contínuo (em maquinaria) no 2º EIC. Quadro: PCA pequena → assintomática (sopro). PCA grande → ICC no 1º mês (prematuros): taquipneia, má alimentação. Fechamento: indometacina IV (prematuros <1.500g no 1º mês), ibuprofeno ou fechamento percutâneo (crianças e adultos, se hemodinamicamente significativo). Todos: profilaxia de endocardite infecciosa (exceto CIA, mas sim para CIV e PCA).",
                tags = listOf("pediatria", "cia", "civ", "pca", "cardiopatia"), citation = "Diretriz SBP 2023 - Cardiopatia Congênita"),
            LibraryContentItem(id = "peds_028", title = "Leucemia linfoblástica aguda infantil — protocolo BFM", category = "CLINICA_MEDICA",
                summary = "LLA infantil: quimioterapia por 2-3 anos (indução, consolidação, manutenção). Prognóstico favorável (80% de cura).",
                content = "Leucemia Linfoblástica Aguda (LLA) na infância: câncer mais comum em crianças (30% dos CA pediátricos). Pico entre 2-5 anos. Quadro: fadiga, palidez, febre, hematomas/petéquias, dor óssea (sinal precoce), hepatoesplenomegalia, linfadenomegalia. Hemograma: leucocitose (blastos), anemia (Hb <10), plaquetopenia (<100.000). Diagnóstico: mielograma >20% blastos linfoides + citometria de fluxo (imunofenotipagem). Subtipos: pré-B (75%), T (25%). Fatores de risco: leucócitos inicial ≥50.000, idade <1 ou >10 anos, citogenética adversa (t[9;22] — Filadélfia, t[4;11], hipodiploidia), resposta lenta (blastos medulares em D8 ou D15). Tratamento: Protocolo BFM (Berlin-Frankfurt-Münster) ou COG (Children's Oncology Group). Fases: 1) Indução (4-6 sem): vincristina, corticoide, L-asparaginase, daunorrubicina. Profilaxia SNC (metotrexato intratecal). 2) Consolidação (2-3 meses): ciclofosfamida, citarabina, 6-MP. 3) Manutenção (2-3 anos): metotrexato semanal + 6-MP diário, com pulsos de vincristina + corticoide a cada 3-6 meses. Prognóstico: sobrevida em 5 anos 85-90% em crianças (padrão-risco, BFM-IC). Refratários ou recidiva: transplante de medula óssea (alogênico). A LLA infantil é um dos grandes sucessos da oncologia pediátrica (em 1960, sobrevida <5%). Efeitos tardios: cardiotoxicidade (antraciclinas), infertilidade, déficit neurocognitivo, segunda neoplasia. Acompanhamento multidisciplinar.",
                tags = listOf("pediatria", "lla", "leucemia", "quimioterapia", "bfm"), citation = "Diretriz SBP 2023 - Leucemia na Infância"),
            LibraryContentItem(id = "peds_029", title = "Síndrome nefrótica na criança — tratamento", category = "CLINICA_MEDICA",
                summary = "Prednisona 2 mg/kg/dia por 4-6 semanas, depois desmame. Recidiva frequente. Biópsia se resistente.",
                content = "Síndrome Nefrótica (SN) na infância: doença glomerular mais comum em crianças (80% é lesão mínima). Quadro: edema periorbitário (primeiro sinal), edema de tornozelos, ascite, derrame pleural, anasarca. Laboratório: proteinúria nefrótica (≥3,5g/24h em adultos, ou relação proteína/creatinina urinária >2, ou fita +++), hipoalbuminemia (<2,5 g/dL), hiperlipidemia (↑ colesterol, ↑ triglicerídeos). Diagnóstico: clínico-laboratorial. Biópsia renal: não é automática. Indicada se: idade <1a ou >12a, hematúria macroscópica, HAS, ↓ complemento, IRC, corticorresistência. SN congênita (Finnish type) — mau prognóstico. Tratamento inicial: SN dependente de corticoide (primeira crise): Prednisona 2 mg/kg/dia (máx 60 mg/dia) por 4-6 semanas (indução), depois 1,5 mg/kg em dias alternados por 4-6 semanas (desmame). Após 6-8 semanas: 80-90% respondem (proteinúria negativa). Resposta: queda de proteinúria para <1+ em fita ou remissão da proteinuria >3 dias. Recidiva: corticossensível (75%): repetir prednisona 2 mg/kg/dia até remissão, depois desmame. Recidiva frequente: 2 ou mais recidivas em 6 meses: adicionar ciclofosfamida (2 mg/kg/dia VO 8-12 sem) ou inibidor de calcineurina (ciclosporina 3-5 mg/kg/dia ou micofenolato). Corticorresistente (não responde em 8-12 sem): biópsia renal (pode ser GESF, glomerulonefrite membranosa) + imunossupressão prolongada. Suporte: restrição de sódio, diurético se edema intenso (furosemida + espironolactona), albumina IV se anasarca com hipoalbuminemia <1,5 g/dL (controverso). Reposição de albumina não é rotina (risco de EAP) — usar apenas se hipovolemia sintomática. Profilaxia de infecções (pneumococo) + vacinação (imunoglobulina antes? — ver SBP). Tratamento da infecção: ATB guiado por cultura. Cuidado: peritonite bacteriana espontânea (SN + febre + dor abdominal) → paracentese. Acompanhamento: nefrologista, proteinúria de 24h, função renal, albumina, perfil lipídico. A SN de lesão mínima tem excelente prognóstico (95% não progridem para IRC).",
                tags = listOf("pediatria", "síndrome nefrótica", "prednisona", "criança"), citation = "Diretriz SBP 2023 - Síndrome Nefrótica"),
            LibraryContentItem(id = "peds_030", title = "Púrpura de Henoch-Schönlein (vasculite IgA)", category = "CLINICA_MEDICA",
                summary = "Púrpura palpável em MMII + dor abdominal + artralgia + nefrite. Tratar com corticoide se acometimento renal ou dor abdominal intensa.",
                content = "Púrpura de Henoch-Schönlein (PHS) / Vasculite por IgA: vasculite de pequenos vasos com depósito de IgA. 90% em crianças 2-10 anos (pico 4-6 anos). Quadro: púrpura palpável em MMII, nádegas (não trombocitopênica). Dor abdominal (cólica, vômito, sangramento gastrointestinal). Artralgia/artrite (joelhos e tornozelos). Glomerulonefrite (nefrite da PHS) — hematúria, proteinúria, HAS (20-50%). Início: pós-infeccioso (IVAS em 30-50% dos casos). Diagnóstico: clínico (não há exame específico). Biópsia de pele: deposição granular de IgA. Exames: hemograma, plaquetas (normais), função renal, sumário de urina (hematúria, proteinúria), PCR/eletroforese de proteínas. Tratamento: maioria autolimitada (3-6 semanas). Suporte: hidratação, analgesia (paracetamol). Não usar AINEs (evitar por possível efeito renal). Corticoide (prednisona 1 mg/kg/dia por 2-4 semanas com desmame) indicado se: dor abdominal intensa (pode prevenir intussuscepção? evidência controversa), sangramento GI, nefrite (hematúria + proteinúria), orquite. Prevenir: crise renal (nefrite) se proteinúria >1g/24h → biópsia renal: se glomerulonefrite proliferativa difusa com crescentes → pulsoterapia com metilprednisolona (30 mg/kg/dia por 3 dias). A PHS não recorre? pode recorrer 30% (especialmente na nefrite). Prognóstico: >95% das crianças se recuperam completamente em 2-3 meses. Nefrite pode persistir e levar a IRC (5-10% dos que tiveram nefrite grave). A PHS é uma das vasculites mais benignas. Diagnóstico diferencial: púrpura trombocitopênica (PTI), meningococcemia, endocardite bacteriana, reação a drogas, sepse.",
                tags = listOf("pediatria", "henoch-schönlein", "púrpura", "vasculite") , citation = "Diretriz SBP 2023 - Vasculite por IgA"),
            LibraryContentItem(id = "peds_031", title = "Doença de Kawasaki — diagnóstico e tratamento", category = "CLINICA_MEDICA",
                summary = "Febre >5 dias + conjuntivite + lábios fissurados + adenomegalia + exantema + edema mãos/pés. Tratar com IGIV + AAS.",
                content = "Doença de Kawasaki (DK): vasculite sistêmica de médias artérias, principal causa de cardiopatia adquirida em crianças (doença coronariana — aneurisma). Faixa etária: 6 meses - 5 anos. Diagnóstico: febre alta (>39°C, ≥5 dias) + ≥4 dos 5 critérios: 1) Conjuntivite bulbar bilateral não exsudativa. 2) Lábios eritematosos/fissurados/em framboesa, orofaringe hiperemiada. 3) Exantema polimórfico (macular, morbiliforme, escarlatiniforme). 4) Adenomegalia cervical (>1,5cm), geralmente unilateral anterior. 5) Alterações de extremidades: edema agudo de mãos e pés (fase aguda) + descamação periungueal (fase subaguda, 2-3 sem). Tratamento: IGIV (imunoglobulina intravenosa) 2 g/kg EV dose única + AAS 80-100 mg/kg/dia 6/6h até 48h sem febre. Após, AAS 3-5 mg/kg/dia (antiagregante) por 6-8 sem (se ecocardiograma normal) ou continuar se lesão coronariana. A IGIV reduz o risco de aneurisma coronariano de 25% para <5% (confere 90% de benefício). Se febre persiste >36h após IGIV: repetir IGIV (outra dose 2g/kg) ou associar pulsoterapia com metilprednisolona (30 mg/kg/dia por 3 dias). Infliximabe (anti-TNF) também é opção. Ecocardiograma: realizar no diagnóstico, 2 sem, 6 sem. Aneurisma de coronária: dilatados (z-score >2,5), gigante >8mm. Prognóstico: morte por IAM/arritmia/rotura de aneurisma. Seguimento: se sem aneurisma 6-8 sem, liberar (sem restrição); se aneurisma, seguimento com cardio+anticoagulante (AAS + varfarina se gigante). A DK é a 2ª vasculite mais comum na infância (depois de PHS). Etiologia: desconhecida (provável gatilho infeccioso em indivíduo suscetível). A prevalência é maior no Japão? sim, e descendentes de japoneses.",
                tags = listOf("pediatria", "kawasaki", "vasculite", "igiv", "aas"), citation = "Diretriz SBP 2023 - Doença de Kawasaki"),
            LibraryContentItem(id = "peds_032", title = "Síndrome de Kawasaki — prevenir aneurisma coronariano", category = "CLINICA_MEDICA",
                summary = "IGIV (2 g/kg) dentro de 10 dias de febre é o tratamento padrão para prevenir aneurisma coronariano.",
                content = "Prevenção de aneurisma coronariano na Doença de Kawasaki: Padrão ouro: Imunoglobulina intravenosa (IGIV) 2 g/kg EV dose única, em infusão lenta (10-12h). INICIAR o mais rápido possível (dentro de 10 dias de febre, se possível <7 dias). IGIV bloqueia a cascata inflamatória que causa vasculite de coronárias. Reduz a incidência de aneurisma de 25% para <5%. Efeitos colaterais: reação alérgica (rara), meningite asséptica, sobrecarga de volume (cuidado se disfunção cardíaca), febre/piora de sintomas após infusão (6-12h). AAS (ácido acetilsalicílico): em altas doses (80-100 mg/kg/dia 6/6h) inicialmente como anti-inflamatório, depois baixas doses (3-5 mg/kg/dia) como antiagregante. Ecocardiograma seriado: 1) Inicial (ao diagnóstico). 2) 2 semanas. 3) 6-8 semanas (alta). Lesões coronarianas: anomalias da luz (ectasia, aneurisma — geralmente em segmento proximal). Critérios de risco: sexo masculino, idade <6 meses, febre prolongada, KD incompleta, plaquetopenia (<350.000), hipoalbuminemia, PCR elevado persistentemente. Se aneurisma estabelecido: anticoagulação (AAS + varfarina ou + enoxaparina se aneurisma gigante >8mm). A IGIV falha em 10-20% (febre persistente >36h). Repetir dose de IGIV 2 g/kg ou considerar pulso de metilprednisolona. A vacinação (MMR e varicela) deve ser postergada 11 meses após IGIV. Seguimento: se sem aneurisma — liberar para atividades normais. Se aneurisma — cardiológico (teste ergométrico, angioTC/RM coronariana). A DK é a causa mais comum de infarto agudo em crianças e adultos jovens com aneurisma coronariano por Kawasaki. A prevenção do aneurisma é o foco central do tratamento.",
                tags = listOf("pediatria", "kawasaki", "aneurisma", "igiv"), citation = "Diretriz SBP 2023 - Doença de Kawasaki"),
            LibraryContentItem(id = "peds_033", title = "Varicela — tratamento com aciclovir", category = "CLINICA_MEDICA",
                summary = "Aciclovir em imunocomprometidos, formas graves, neonatos ou >12 anos (recomendado). Sintomáticos e higiene para casos leves.",
                content = "Varicela (catapora — VZV primário): doença exantemática febril altamente contagiosa (transmissão respiratória e por contato). Período de incubação: 14-16 dias. Quadro: febre baixa + exantema vesicular em diferentes estágios (mácula → pápula → vesícula → crosta). Prurido intenso. Lesões: tronco → face → extremidades. Mucosas: boca e olhos. Complicações: infecção bacteriana secundária (S. aureus, S. pyogenes — celulite, abscesso, fasciíte necrotizante), pneumonia por VZV (até 10% de adultos, mais grave em gestantes), encefalite, ataxia cerebelar (benigna, mais em crianças <5 anos), síndrome de Reye (se usar AAS), hepatite, púrpura trombocitopênica. Tratamento: leve/moderado (<12 anos, sem fatores de risco): sintomáticos (antitérmicos — EVITAR AAS! usar paracetamol ou ibuprofeno), anti-histamínicos (hidroxizina 1-2 mg/kg/dia) para prurido, banhos de permanganato de potássio (1:40.000). Corticoide tópico (se prurido intenso). Mantenha unhas curtas. Antiviral (aciclovir 20 mg/kg/dose 6/6h [máx 800 mg]) indicado para: imunocomprometidos, neonatos (<28 dias), >12 anos, gestantes, formas graves (pneumonia, encefalite). Iniciar <24h do rash. Neonato exposto VZV: se mãe desenvolve varicela 5 dias antes a 2 dias após parto: imunoglobulina (VariZIG 125 U/10 kg IM, máx 625 U) + aciclovir. Profilaxia pós-exposição (imune a IgG): vacina VZV (até 5 dias pós-exposição previne ou atenua a doença). VariZIG: para imunocomprometidos, gestantes, RN expostos. Isolamento: 5-7 dias após início das lesões (até todas virarem crosta). A vacina tetra viral (SCR + varicela) é segura e eficaz. Reduz casos graves e internações. A vacina de 2 doses (1 ano e 4 anos) reduziu em 90% os casos.",
                tags = listOf("pediatria", "varicela", "aciclovir", "catapora"), citation = "Diretriz SBP 2023 - Varicela"),
            LibraryContentItem(id = "peds_034", title = "Impetigo — tratamento", category = "CLINICA_MEDICA",
                summary = "Impetigo não bolhoso: mupirocina tópica (3x/dia por 5-7 dias). Forma disseminada ou bolhosa: cefalexina VO 7 dias.",
                content = "Impetigo: infecção cutânea bacteriana superficial (S. aureus ou S. pyogenes). Formas clínicas: Não bolhoso (crosta melicérica) — lesões crostosas amareladas (bem características). Pode ter linfadenopatia. Muito contagioso (creche/escola). Bolhoso — toxina esfoliatina (S. aureus) → bolhas flácidas superficiais. Diagnóstico: clínico. Cultura de secreção (se falha de tratamento). Tratamento: Impetigo não bolhoso (localizado): limpeza com água e sabão + mupirocina tópica 2% (pomada) 3x/dia por 5-7 dias. Alternativa: ácido fusídico tópico ou gentamicina tópica. Se disseminado (múltiplas lesões), bolhoso, ou falha de tratamento tópico: antibiótico sistêmico — Cefalexina 25-50 mg/kg/dia 12/12h (adultos 500 mg 6/6h) por 7 dias. Alternativa: amoxicilina-clavulanato (50 mg/kg/dia) ou clindamicina (20-30 mg/kg/dia), ou azitromicina (se alergia). Se MRSA: clindamicina ou TMP-SMX. Complicações: celulite, abscesso, glomerulonefrite pós-estreptocócica (GNDA — apenas se S. pyogenes, não prevenível por ATB). Febre reumática: NÃO ocorre após impetigo (GAS não causa FR por via cutânea). Prevenção: banhos diários, roupas limpas, cortar unhas, lavar as mãos. A contaminação por contato: evitar compartilhar toalhas/roupas de cama. A criança pode frequentar creche após 24h de tratamento eficaz (não bolhoso). Limpar superfícies (desinfetante). Acomete mais crianças em creche ou com condições de higiene precárias.",
                tags = listOf("pediatria", "impetigo", "mupirocina", "cefalexina"), citation = "Diretriz SBP 2023 - Impetigo"),
            LibraryContentItem(id = "peds_035", title = "Vacinação infantil — calendário SUS", category = "CLINICA_MEDICA",
                summary = "Calendário básico SUS: BCG (1 dose ao nascer), Hepatite B (0, 2, 4 meses), Penta (2, 4, 6m), VIP/VOP (2, 4, 6m + reforços), Pneumocócica 10v (2, 4, 12m), Meningocócica C (3, 5, 12m), SCR (12m e 4a), DTP (15m e 4a), HPV (9-14a meninas, 11-14a meninos).",
                content = "Calendário Nacional de Vacinação (SUS — 2024): Ao nascer: BCG (tuberculose) e Hepatite B (HBV). 2 meses: Penta (DTP-Hib-HB), VIP (poliomielite injetável), Pneumocócica 10-valente (PCV10), Rotavírus. 3 meses: Meningocócica C (MNC). 4 meses: Penta, VIP, PCV10, Rotavírus. 5 meses: MNC. 6 meses: Penta, VIP, Influenza (anual, a partir de 6 meses). 9 meses: Febre Amarela (FA). 12 meses: PCV10 (reforço), MNC, SCR (tríplice viral sarampo-caxumba-rubéola). 15 meses: DTP (1º reforço), VOP (poliomielite oral), Hepatite A (HAV), Tetra viral (SCR+VZ). 4 anos: DTP (2º reforço), VOP (2º reforço), SCR (2ª dose). 9-14 anos: HPV (meninas 9-14, meninos 11-14 — 2 doses). 9-45 anos: dTpa (gestante a cada gestação). Adolescentes e adultos: reforço dT (tétano e difteria) a cada 10 anos. Idosos >60 anos: vacina Influenza + Pneumocócica 23-valente + dTpa + Herpes Zoster (<50 anos apenas com comorbidade). A vacina contra COVID-19 está no calendário. Contraindicações: geral — alergia a componente, doença febril aguda. Não contraindica: doença leve (IVAS), uso de ATB, prematuridade, peso baixo, desnutrição, alergia ao ovo (vacina sarampo/caxumba/rubéola pode ser aplicada, mas com cuidado — mas a vacina da febre amarela é contraindicada se alergia ao ovo). Importância: as vacinas salvaram mais vidas do que qualquer outro procedimento médico na história (segundo a OMS). A adesão ao calendário vacinal do SUS é obrigatória e protege não apenas o indivíduo, mas a população (imunidade de rebanho).",
                tags = listOf("pediatria", "vacinação", "calendário", "sus"), citation = "Diretriz MS Brasil 2023 - Calendário Nacional de Vacinação"),
        )
    )

    // ═══════════════════════════════════════════════════════════════
    // PACOTE: GINECOLOGIA E OBSTETRÍCIA — 35 tópicos
